'use server';

import { cookies } from 'next/headers';

// ---- AUTHENTICATION SESSION ----

export async function setAuthSession(token: string, user: any) {
  const cookieStore = await cookies();

  // Set Token Cookie
  cookieStore.set('unifoods_token', token, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'lax',
    maxAge: 30 * 24 * 60 * 60, // 30 days
    path: '/',
  });

  // Set User Cookie (can be read by client components for basic ID data if needed, but keeping HttpOnly is safer)
  cookieStore.set('unifoods_user', JSON.stringify(user), {
    httpOnly: false, // We often need to parse this quickly on client without calling context if doing initial hydration, though Context usually calls getAuthSession
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'lax',
    maxAge: 30 * 24 * 60 * 60,
    path: '/',
  });
}

export async function getAuthSession() {
  const cookieStore = await cookies();
  const token = cookieStore.get('unifoods_token')?.value || null;
  const userStr = cookieStore.get('unifoods_user')?.value || null;

  let user = null;
  if (userStr) {
    try {
      user = JSON.parse(userStr);
    } catch (e) {
      console.error("Failed to parse user session", e);
    }
  }

  return { token, user };
}

export async function clearAuthSession() {
  const cookieStore = await cookies();
  cookieStore.delete('unifoods_token');
  cookieStore.delete('unifoods_user');
}

// ---- ORDER CHECKOUT SESSION ----

export async function setOrderSession(orderId: string, orderData: any) {
  const cookieStore = await cookies();

  // Storing lastOrderId
  cookieStore.set('lastOrderId', orderId, {
    httpOnly: false,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'lax',
    maxAge: 24 * 60 * 60, // 1 day
    path: '/',
  });

  // Optional: Storing full order data if the page heavily relies on it
  if (orderData) {
    cookieStore.set('lastOrder', JSON.stringify(orderData), {
        httpOnly: false,
        secure: process.env.NODE_ENV === 'production',
        sameSite: 'lax',
        maxAge: 24 * 60 * 60, // 1 day
        path: '/',
    });
  }
}

export async function getOrderSession() {
  const cookieStore = await cookies();
  const lastOrderId = cookieStore.get('lastOrderId')?.value || null;
  const lastOrderStr = cookieStore.get('lastOrder')?.value || null;

  let lastOrder = null;
  if (lastOrderStr) {
    try {
      lastOrder = JSON.parse(lastOrderStr);
    } catch (e) {
        console.error("Failed to parse order session", e);
    }
  }

  return { lastOrderId, lastOrder };
}

export async function clearOrderSession() {
  const cookieStore = await cookies();
  cookieStore.delete('lastOrderId');
  cookieStore.delete('lastOrder');
}

"use client";

import { useCart } from '@/lib/context/CartContext';
import Header from '@/components/Header';
import Footer from '@/components/Footer';
import CartItem from '@/components/cart/CartItem';
import CartSummary from '@/components/cart/CartSummary';
import EmptyCart from '@/components/cart/EmptyCart';
import ProductCard from '@/components/products/ProductCard';
import { Trash2, Loader2 } from 'lucide-react';
import Link from 'next/link';
import { useEffect, useState } from 'react';
import { Product } from '@/lib/types/product';
import PageTransition from "@/components/ui/PageTransition";
import { motion, AnimatePresence } from 'framer-motion';
import SkeletonCard from '@/components/products/SkeletonCard';

// Safe API Base URL retrieval
const getApiBase = () => {
  if (process.env.NEXT_PUBLIC_API_BASE_URL) return process.env.NEXT_PUBLIC_API_BASE_URL;
  return "https://horeca-backend-six.vercel.app"; // Fallback to known backend
};

function mapRawToProduct(raw: any): Product | null {
  if (!raw) return null;
  const id = raw._id ?? raw.id ?? raw.productId;
  if (!id) return null;

  return {
    id: String(id),
    name: raw.name ?? raw.title ?? 'Unnamed product',
    description: raw.description ?? raw.desc ?? '',
    price: typeof raw.price === 'number' ? raw.price : Number(raw.price ?? 0),
    discount: typeof raw.discount === 'number' ? raw.discount : (typeof raw.offerPercentage === 'number' ? raw.offerPercentage : 0),
    image:
      typeof raw.image === 'string'
        ? raw.image
        : Array.isArray(raw.images) && raw.images.length
          ? (raw.images[0].url ?? raw.images[0])
          : '',
    unit: raw.unit ?? 'pcs',
    minOrder: typeof raw.minOrder === 'number' ? raw.minOrder : (raw.minOrder ?? 1),
    rating: typeof raw.rating === 'number' ? raw.rating : (raw.averageRating ?? 0),
    reviews: typeof raw.reviews === 'number' ? raw.reviews : (raw.totalReviews ?? 0),
    category: raw.category ?? raw.categoryName ?? raw.categoryId ?? '',
    badge: raw.badge ?? (raw.isFeatured ? 'Featured' : undefined),
    inStock: typeof raw.inStock === 'boolean' ? raw.inStock : (typeof raw.stockQuantity === 'number' ? raw.stockQuantity > 0 : true),
    ...(raw as any),
  } as Product;
}

export default function CartPage() {
  const { items, updateQuantity, removeItem, clearCart, itemCount, subtotal } = useCart();
  const [recommendations, setRecommendations] = useState<Product[]>([]);
  const [loadingRecs, setLoadingRecs] = useState(false);
  const [apiBase, setApiBase] = useState("");

  useEffect(() => {
    setApiBase(getApiBase());
  }, []);

  useEffect(() => {
    const fetchRecommendations = async () => {
      const BaseURL = getApiBase();

      // Strict check: If cart is empty, do NOT show recommendations
      if (items.length === 0) {
        setRecommendations([]);
        return;
      }

      setLoadingRecs(true);
      try {
        console.log("🛠️ Starting Recommendation Fetch...");

        // Extract unique categories from cart items safely handling object/string
        const names = items.map(item => {
          const cat = item.product.category as any;
          if (!cat) return null;
          if (typeof cat === 'string') return cat;
          if (typeof cat === 'object' && cat.name) return cat.name;
          return null;
        }).filter(Boolean);

        const categories = [...new Set(names)];
        console.log("📂 Extracted Categories:", categories);

        // 1. Fetch products for each category
        let promises: Promise<any>[] = [];
        if (categories.length > 0) {
          promises = categories.map(async (category) => {
            try {
              const url = `${BaseURL}/api/products?category=${encodeURIComponent(String(category))}&limit=4`;
              const res = await fetch(url);
              if (!res.ok) return [];
              const json = await res.json();
              const list = json.products || json.data?.items || json.data || [];
              return Array.isArray(list) ? list : [];
            } catch (e) {
              return [];
            }
          });
        }

        const results = await Promise.all(promises);

        // IMPORTANT: Map raw data to Product objects to ensure `id` exists before filtering
        let fetchedProducts = results.flat().map(mapRawToProduct).filter((p): p is Product => p !== null);

        // 2. Filter out products that are already in the cart
        const cartProductIds = new Set(items.map(item => item.product?.id).filter(Boolean));
        let filtered = fetchedProducts
          .filter((p) => !cartProductIds.has(p.id))
          .filter((p, index, self) =>
            index === self.findIndex((t) => t.id === p.id)
          );

        // 3. Fallback: If we have fewer than 4 items, fetch general products (ONLY if cart is not empty)
        if (filtered.length < 4) {
          console.log("🔄 Triggering Fallback Recommendation...");
          try {
            const url = `${BaseURL}/api/products?limit=12`;
            const res = await fetch(url);
            if (res.ok) {
              const json = await res.json();
              const rawGeneral = (json.products || json.data?.items || json.data || []);

              if (Array.isArray(rawGeneral)) {
                const mappedGeneral = rawGeneral.map(mapRawToProduct).filter((p): p is Product => p !== null);

                const existingRecIds = new Set(filtered.map(p => p.id));
                const additional = mappedGeneral.filter((p) =>
                  !cartProductIds.has(p.id) && !existingRecIds.has(p.id)
                );

                filtered = [...filtered, ...additional];
                console.log("✅ Fallback added items:", additional.length);
              }
            }
          } catch (e) {
            console.error("❌ Failed to fetch fallback products", e);
          }
        }

        // 4. Final slice to 4 items
        const finalRecs = filtered.slice(0, 4);
        console.log("🏁 Final Recommendations:", finalRecs);
        setRecommendations(finalRecs);

      } catch (err) {
        console.error("🔥 Critical Error in Recommendation Logic", err);
      } finally {
        setLoadingRecs(false);
      }
    };

    fetchRecommendations();
  }, [items]);

  return (
    <PageTransition>
      <div className="min-h-screen flex flex-col">
        <Header />

        <main className="flex-grow bg-[#FAFAF7] py-8">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">

            {/* Breadcrumb */}
            <div className="mb-6">
              <nav className="flex items-center gap-2 text-sm text-gray-600">
                <Link href="/" className="hover:text-[#D97706] transition-colors">Home</Link>
                <span>/</span>
                <span className="text-[#111827] font-medium">Shopping Cart</span>
              </nav>
            </div>

            {/* Page Header */}
            <div className="mb-8 flex items-center justify-between">
              <div>
                <h1 className="text-4xl font-light text-[#111827] mb-2">Shopping Cart</h1>
                <p className="text-gray-600">
                  {itemCount > 0 ? `${itemCount} ${itemCount === 1 ? 'item' : 'items'} in your cart` : 'Your cart is empty'}
                </p>
              </div>

              {items.length > 0 && (
                <button
                  onClick={clearCart}
                  className="flex items-center gap-2 px-4 py-2 text-red-500 hover:bg-red-50 rounded-full transition-all text-sm font-medium"
                >
                  <Trash2 size={16} />
                  Clear Cart
                </button>
              )}
            </div>

            {/* Cart Content */}
            <AnimatePresence mode="wait">
              {items.length === 0 ? (
                <motion.div
                  key="empty"
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: -10 }}
                >
                  <EmptyCart />
                </motion.div>
              ) : (
                <div className="grid lg:grid-cols-3 gap-8">

                  {/* Cart Items List */}
                  <div className="lg:col-span-2 space-y-4">
                    <AnimatePresence initial={false}>
                      {items.map((item) => (
                        <motion.div
                          key={item.product.id}
                          initial={{ opacity: 0, height: 0 }}
                          animate={{ opacity: 1, height: 'auto' }}
                          exit={{ opacity: 0, height: 0, overflow: 'hidden' }}
                          transition={{ duration: 0.3 }}
                        >
                          <CartItem
                            item={item}
                            onUpdateQuantity={updateQuantity}
                            onRemove={removeItem}
                          />
                        </motion.div>
                      ))}
                    </AnimatePresence>

                    {/* Mobile Summary */}
                    <div className="lg:hidden mt-6">
                      <CartSummary subtotal={subtotal} itemCount={itemCount} />
                    </div>
                  </div>

                  {/* Desktop Summary */}
                  <div className="hidden lg:block">
                    <div className="sticky top-24">
                      <CartSummary subtotal={subtotal} itemCount={itemCount} />
                    </div>
                  </div>
                </div>
              )}
            </AnimatePresence>

            {/* Recommendation Section - Only visible if items exist */}
            {items.length > 0 && (
              <div className="mt-16">
                <div className="flex items-center justify-between mb-6">
                  <h3 className="text-2xl font-light text-[#111827]">You might also like</h3>
                  <Link href="/products" className="text-[#D97706] hover:text-[#B45309] font-medium transition-colors">
                    Browse all products →
                  </Link>
                </div>

                {loadingRecs ? (
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                    {Array.from({ length: 4 }).map((_, i) => (
                      <SkeletonCard key={i} />
                    ))}
                  </div>
                ) : recommendations.length > 0 ? (
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                    {recommendations.map(product => (
                      <ProductCard key={product.id} product={product} />
                    ))}
                  </div>
                ) : (
                  <div className="bg-white rounded-2xl p-8 text-center text-gray-500 soft-shadow">
                    No specific recommendations found.
                    <Link href="/products" className="text-[#D97706] ml-1 hover:underline">
                      Continue shopping
                    </Link>
                  </div>
                )}
              </div>
            )}

          </div>
        </main>

        <Footer />
      </div>
    </PageTransition>
  );
}

'use client';

import React, { useEffect, useState } from 'react';
import Image from 'next/image';
import Header from '@/components/Header';
import Footer from '@/components/Footer';
import { Search, Loader2 } from 'lucide-react';
import { categories as fallbackCategories } from '@/lib/data';
import SkeletonCategoryCard from '@/components/categories/SkeletonCategoryCard';
import PageTransition from '@/components/ui/PageTransition';
import { motion, AnimatePresence } from 'framer-motion';

const API_BASE = (process.env.NEXT_PUBLIC_API_BASE_URL ?? '').trim();

function buildApiUrl(path: string) {
    if (API_BASE) {
        const base = API_BASE.replace(/\/+$/, '');
        return `${base}/${path.replace(/^\/+/, '')}`;
    }
    return `/${path.replace(/^\/+/, '')}`;
}

function mapCategory(raw: any) {
    if (!raw) return null;
    const id = raw._id ?? raw.id ?? raw.categoryId ?? raw.name ?? raw.title;
    const name = raw.name ?? raw.categoryName ?? raw.title ?? raw.category ?? 'Unnamed';
    const image =
        (typeof raw?.image === 'string' && raw.image) ||
        (raw?.image?.url && String(raw.image.url)) ||
        raw?.imageUrl ||
        raw?.thumbnail ||
        raw?.photo ||
        null;
    return { id: String(id ?? name), name, image };
}

export default function CategoriesPage() {
    const [cats, setCats] = useState<any[] | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [searchQuery, setSearchQuery] = useState('');

    // Fallback
    const mappedFallback = fallbackCategories.map((c: any) => ({
        id: String(c.id ?? c._id ?? c.name),
        name: c.name ?? c.title ?? 'Unnamed',
        image: c.image ?? c.imageUrl ?? `/images/categories/${c.id}.jpg`,
    }));

    useEffect(() => {
        let active = true;
        (async () => {
            try {
                setLoading(true);
                const url = buildApiUrl('api/categories');
                const res = await fetch(url);
                if (!res.ok) throw new Error('Failed to fetch');
                const json = await res.json();

                let list: any[] = [];
                if (Array.isArray(json)) list = json;
                else if (Array.isArray(json?.data)) list = json.data;
                else if (Array.isArray(json?.categories)) list = json.categories;
                else if (Array.isArray(json?.results)) list = json.results;
                else if (Array.isArray(json?.data?.items)) list = json.data.items;
                else {
                    // attempt to find first array in object
                    const arr = Object.values(json || {}).find((v: any) => Array.isArray(v));
                    if (Array.isArray(arr)) list = arr;
                }

                const mapped = (list || []).map(mapCategory).filter(Boolean);
                if (active) {
                    // correct: if empty, try fallback?
                    if (mapped.length > 0) {
                        setCats(mapped);
                    } else {
                        console.warn("Categories API returned empty list, using fallback.");
                        setCats(mappedFallback);
                    }
                    setLoading(false);
                }
            } catch (err) {
                console.error(err);
                if (active) {
                    setCats(mappedFallback); // Use fallback on error
                    setLoading(false);
                }
            }
        })();
        return () => { active = false; };
    }, []);

    const displayCats = cats || mappedFallback;
    const filteredCats = displayCats.filter(c => c.name.toLowerCase().includes(searchQuery.toLowerCase()));

    return (
        <PageTransition>
            <div className="min-h-screen bg-gray-50 flex flex-col font-sans">
                <Header />

                {/* Hero Section */}
                <div className="py-12">
                    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
                        <motion.h1
                            initial={{ opacity: 0, y: -20 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: 0.1 }}
                            className="text-3xl md:text-4xl font-serif font-bold text-[#111827] mb-4"
                        >
                            Explore Categories
                        </motion.h1>
                        <motion.p
                            initial={{ opacity: 0, y: -20 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: 0.2 }}
                            className="text-base text-gray-600 max-w-2xl mx-auto mb-8"
                        >
                            Find everything you need for your bakery, from premium ingredients to essential tools, organized for your convenience.
                        </motion.p>

                        {/* Search Bar */}
                        <motion.div
                            initial={{ opacity: 0, scale: 0.95 }}
                            animate={{ opacity: 1, scale: 1 }}
                            transition={{ delay: 0.3 }}
                            className="relative max-w-md mx-auto"
                        >
                            <input
                                type="text"
                                placeholder="Search categories..."
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                className="w-full pl-12 pr-4 py-4 rounded-full border border-gray-200 focus:border-[#D97706] focus:ring-2 focus:ring-[#D97706]/20 outline-none shadow-sm transition-all"
                            />
                            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                        </motion.div>
                    </div>
                </div>

                {/* Main Content */}
                <main className="flex-grow py-16">
                    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                        {loading ? (
                            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6 md:gap-8">
                                {Array.from({ length: 15 }).map((_, i) => (
                                    <SkeletonCategoryCard key={i} />
                                ))}
                            </div>
                        ) : filteredCats.length === 0 ? (
                            <div className="text-center py-20">
                                <p className="text-xl text-gray-600">No categories found matching "{searchQuery}"</p>
                                <button
                                    onClick={() => setSearchQuery('')}
                                    className="mt-4 text-[#D97706] font-medium hover:underline"
                                >
                                    Clear Search
                                </button>
                            </div>
                        ) : (
                            <motion.div
                                initial="hidden"
                                animate="show"
                                variants={{
                                    hidden: { opacity: 0 },
                                    show: {
                                        opacity: 1,
                                        transition: {
                                            staggerChildren: 0.05
                                        }
                                    }
                                }}
                                className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6 md:gap-8"
                            >
                                <AnimatePresence>
                                    {filteredCats.map((category) => (
                                        <motion.a
                                            layout
                                            variants={{
                                                hidden: { opacity: 0, y: 20 },
                                                show: { opacity: 1, y: 0 }
                                            }}
                                            key={category.id}
                                            href={`/products?category=${encodeURIComponent(category.name)}`}
                                            className="group block bg-white rounded-2xl overflow-hidden shadow-sm hover:shadow-xl transition-all duration-300 transform border border-gray-100"
                                        >
                                            <div className="relative aspect-square overflow-hidden bg-gray-100">
                                                <Image
                                                    src={category.image || '/images/placeholder.png'}
                                                    alt={category.name}
                                                    fill
                                                    className="object-cover group-hover:scale-110 transition-transform duration-500"
                                                    unoptimized={Boolean(category.image && typeof category.image === 'string' && category.image.startsWith('http'))}
                                                />
                                                <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors duration-300" />
                                            </div>
                                            <div className="p-4 text-center">
                                                <h3 className="font-medium text-gray-900 group-hover:text-[#D97706] transition-colors line-clamp-2">
                                                    {category.name}
                                                </h3>
                                            </div>
                                        </motion.a>
                                    ))}
                                </AnimatePresence>
                            </motion.div>
                        )}
                    </div>
                </main>

                <Footer />
            </div>
        </PageTransition>
    );
}

