'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { useCart } from '@/lib/context/CartContext';
import Header from '@/components/Header';
import Footer from '@/components/Footer';
import ShippingForm from '@/components/checkout/ShippingForm';
import PaymentMethod from '@/components/checkout/PaymentMethod';
import OrderReview from '@/components/checkout/OrderReview';
import { ShippingAddress, PaymentMethod as PaymentMethodType, CheckoutStep } from '@/lib/types/checkout';
import { Check } from 'lucide-react';
import Link from 'next/link';
import { useEffect } from 'react';
import { useAuth } from '@/lib/context/AuthContext';
import PageTransition from "@/components/ui/PageTransition";

export default function CheckoutPage() {
  const router = useRouter();
  const { items, subtotal, clearCart } = useCart();
  const [currentStep, setCurrentStep] = useState<CheckoutStep>('shipping');
  const [shippingAddress, setShippingAddress] = useState<ShippingAddress | null>(null);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethodType>('cod');
  const [isPlacingOrder, setIsPlacingOrder] = useState(false);
  const { user } = useAuth();
  const [mounted, setMounted] = useState(false);


  console.log("User ", user);

  useEffect(() => {
    setMounted(true);
  }, []);

  console.log(shippingAddress);

  // // Redirect if cart is empty
  // useEffect(() => {
  //   if (items.length === 0) {
  //     router.push('/cart');
  //   }
  // }, [items, router]);


  // Calculate order totals (same as cart)
  const discount = 0; // Would come from applied coupon
  const subtotalAfterDiscount = subtotal - discount;
  const tax = subtotalAfterDiscount * 0.18;
  const shipping = subtotal >= 500 ? 0 : 20;
  const platformFee = 5;
  const total = subtotalAfterDiscount + tax + shipping + platformFee;

  const steps = [
    { id: 'shipping' as CheckoutStep, label: 'Shipping', number: 1 },
    { id: 'payment' as CheckoutStep, label: 'Payment', number: 2 },
    { id: 'review' as CheckoutStep, label: 'Review', number: 3 },
  ];

  const currentStepIndex = steps.findIndex((s) => s.id === currentStep);

  const handleShippingSubmit = (address: ShippingAddress) => {
    setShippingAddress(address);
    setCurrentStep('payment');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handlePaymentSubmit = (method: PaymentMethodType) => {
    setPaymentMethod(method);
    setCurrentStep('review');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handlePlaceOrder = async () => {
    setIsPlacingOrder(true);

    // Simulate API call
    await new Promise((resolve) => setTimeout(resolve, 2000));

    // Generate order
    const orderId = `ORD-${Date.now()}`;
    const orderNumber = `#${Math.floor(100000 + Math.random() * 900000)}`;

    const order = {
      id: orderId,
      orderNumber,
      date: new Date().toISOString(),
      status: 'confirmed' as const,
      shippingAddress: shippingAddress!,
      paymentMethod,
      items: items.map((item) => ({
        productId: item.product.id,
        productName: item.product.name,
        quantity: item.quantity,
        price: item.product.discount
          ? item.product.price - (item.product.price * item.product.discount / 100)
          : item.product.price,
        image: item.product.image,
      })),
      subtotal,
      discount,
      tax,
      shipping,
      platformFee,
      total,
    };

    // // Save to localStorage
    // localStorage.setItem('lastOrder', JSON.stringify(order));

    // Save order to localStorage
    localStorage.setItem("lastOrder", JSON.stringify(order));
    localStorage.setItem("lastOrderId", order.id);

    // Clear cart
    clearCart();

    // Redirect to confirmation
    // router.push(`/order-confirmation?order=${orderId}`);
    router.push(`/order-confirmation?order=${order.id}`);
  };

  return (
    <PageTransition>
      <div className="min-h-screen flex flex-col">
        <Header />

        <main className="flex-grow bg-[#FAFAF7] py-8">
          <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8">
            {/* Breadcrumb */}
            <div className="mb-6">
              <nav className="flex items-center gap-2 text-sm text-gray-600">
                <Link href="/" className="hover:text-[#D97706] transition-colors">Home</Link>
                <span>/</span>
                <a href="/cart" className="hover:text-[#D97706] transition-colors">Cart</a>
                <span>/</span>
                <span className="text-[#111827] font-medium">Checkout</span>
              </nav>
            </div>

            {/* Page Header */}
            <div className="mb-8">
              <h1 className="text-4xl font-light text-[#111827] mb-2">
                Checkout
              </h1>
              <p className="text-gray-600">
                Complete your order in just a few steps
              </p>
            </div>

            {/* Step Indicator */}
            <div className="mb-8">
              <div className="bg-white rounded-2xl soft-shadow p-6">
                <div className="flex items-center justify-between">
                  {steps.map((step, index) => {
                    const isCompleted = index < currentStepIndex;
                    const isCurrent = step.id === currentStep;

                    return (
                      <div key={step.id} className="flex items-center flex-1">
                        {/* Step Circle */}
                        <div className="flex flex-col items-center">
                          <div
                            className={`w-12 h-12 rounded-full flex items-center justify-center font-semibold transition-all ${isCompleted
                              ? 'bg-[#D97706] text-white'
                              : isCurrent
                                ? 'bg-[#D97706] text-white ring-4 ring-[#D97706]/20'
                                : 'bg-gray-200 text-gray-500'
                              }`}
                          >
                            {isCompleted ? (
                              <Check size={24} strokeWidth={3} />
                            ) : (
                              step.number
                            )}
                          </div>
                          <span
                            className={`mt-2 text-sm font-medium ${isCurrent ? 'text-[#D97706]' : 'text-gray-600'
                              }`}
                          >
                            {step.label}
                          </span>
                        </div>

                        {/* Connector Line */}
                        {index < steps.length - 1 && (
                          <div
                            className={`flex-1 h-1 mx-4 rounded transition-all ${index < currentStepIndex ? 'bg-[#D97706]' : 'bg-gray-200'
                              }`}
                          />
                        )}
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>

            {/* Step Content */}
            <div>
              {currentStep === 'shipping' && (
                <ShippingForm
                  onSubmit={handleShippingSubmit}
                  initialData={shippingAddress || undefined}
                />
              )}

              {currentStep === 'payment' && (
                <div className="space-y-4">
                  <button
                    onClick={() => setCurrentStep('shipping')}
                    className="text-[#D97706] hover:text-[#B45309] font-medium text-sm"
                  >
                    ← Back to Shipping
                  </button>
                  <PaymentMethod
                    onSubmit={handlePaymentSubmit}
                    initialMethod={paymentMethod}
                  />
                </div>
              )}

              {currentStep === 'review' && shippingAddress && (
                <div className="space-y-4">
                  <button
                    onClick={() => setCurrentStep('payment')}
                    className="text-[#D97706] hover:text-[#B45309] font-medium text-sm"
                  >
                    ← Back to Payment
                  </button>
                  {/* <OrderReview
                  shippingAddress={shippingAddress}
                  paymentMethod={paymentMethod}
                  items={items}
                  subtotal={subtotal}
                  discount={discount}
                  tax={tax}
                  shipping={shipping}
                  total={total}
                  onEditShipping={() => setCurrentStep('shipping')}
                  onEditPayment={() => setCurrentStep('payment')}
                  onPlaceOrder={handlePlaceOrder}
                  isPlacingOrder={isPlacingOrder}
                /> */}

                  <OrderReview
                    shippingAddress={shippingAddress}
                    paymentMethod={paymentMethod}
                    items={items}
                    subtotal={subtotal}
                    discount={discount}
                    tax={tax}
                    shipping={shipping}
                    total={total}
                    onEditShipping={() => setCurrentStep('shipping')}
                    onEditPayment={() => setCurrentStep('payment')}
                    platformFee={platformFee}
                  />

                </div>
              )}
            </div>
          </div>
        </main>

        <Footer />
      </div>
    </PageTransition>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useAuth } from '@/lib/context/AuthContext';
import Header from '@/components/Header';
import Footer from '@/components/Footer';
import { Bell, Check, Trash2, AlertTriangle, Info, CheckCircle, XCircle, Filter, Calendar } from 'lucide-react';
import Link from 'next/link';
import { format, isToday, isYesterday } from 'date-fns';
import PageTransition from '@/components/ui/PageTransition';

const API_BASE = process.env.NEXT_PUBLIC_API_BASE_URL || "http://horeca-backend-six.vercel.app";

type Notification = {
    _id: string;
    title: string;
    message: string;
    type: 'info' | 'warning' | 'error' | 'success';
    isRead: boolean;
    createdAt: string;
    metadata?: any;
};

export default function NotificationsPage() {
    const { user, token, isAuthenticated } = useAuth();
    const [notifications, setNotifications] = useState<Notification[]>([]);
    const [loading, setLoading] = useState(true);
    const [filter, setFilter] = useState<'all' | 'unread'>('all');

    useEffect(() => {
        if (isAuthenticated && user && token) {
            fetchNotifications();
        } else if (!loading) {
            // Optional: Handle unauth state
        }
    }, [isAuthenticated, user, token]);

    const fetchNotifications = async () => {
        try {
            const userId = (user as any)?.id || (user as any)?._id;
            const res = await fetch(`${API_BASE}/api/notifications?userId=${userId}`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const data = await res.json();
            if (data.success) {
                setNotifications(data.data);
            }
        } catch (error) {
            console.error("Failed to fetch notifications", error);
        } finally {
            setLoading(false);
        }
    };

    const markAsRead = async (id: string) => {
        try {
            // Optimistic update
            setNotifications(prev => prev.map(n => n._id === id ? { ...n, isRead: true } : n));

            await fetch(`${API_BASE}/api/notifications/${id}`, {
                method: 'PATCH',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify({ isRead: true })
            });
        } catch (error) {
            console.error(error);
        }
    };

    const deleteNotification = async (id: string) => {
        try {
            // Optimistic update
            setNotifications(prev => prev.filter(n => n._id !== id));

            await fetch(`${API_BASE}/api/notifications/${id}`, {
                method: 'DELETE',
                headers: { 'Authorization': `Bearer ${token}` }
            });
        } catch (error) {
            console.error(error);
        }
    };

    const clearAll = async () => {
        if (!confirm("Are you sure you want to clear all notifications?")) return;
        try {
            const userId = (user as any)?.id || (user as any)?._id;
            await fetch(`${API_BASE}/api/notifications?userId=${userId}`, {
                method: 'DELETE',
                headers: { 'Authorization': `Bearer ${token}` }
            });
            setNotifications([]);
        } catch (error) {
            console.error(error);
        }
    };

    const getIcon = (type: string) => {
        switch (type) {
            case 'warning': return <AlertTriangle className="w-5 h-5 text-amber-600" />;
            case 'error': return <XCircle className="w-5 h-5 text-red-600" />;
            case 'success': return <CheckCircle className="w-5 h-5 text-emerald-600" />;
            default: return <Info className="w-5 h-5 text-[#D97706]" />;
        }
    };

    // Filter Logic
    const filteredNotifications = notifications.filter(n => {
        if (filter === 'unread') return !n.isRead;
        return true;
    });

    // Group by Date
    const groupedNotifications = filteredNotifications.reduce((groups, notif) => {
        const date = new Date(notif.createdAt);
        let key = 'Earlier';
        if (isToday(date)) key = 'Today';
        else if (isYesterday(date)) key = 'Yesterday';

        if (!groups[key]) groups[key] = [];
        groups[key].push(notif);
        return groups;
    }, {} as Record<string, Notification[]>);

    const groupOrder = ['Today', 'Yesterday', 'Earlier'];

    return (
        <div className="min-h-screen bg-[#FAFAF7] flex flex-col font-sans">
            <Header />

            <main className="container mx-auto px-4 md:px-6 py-12 max-w-5xl flex-grow">
                {/* Header Section */}
                <div className="flex flex-col md:flex-row md:items-center justify-between mb-10 gap-4">
                    <div>
                        <h1 className="text-3xl font-bold text-[#111827] flex items-center gap-3">
                            <span className="bg-gradient-to-br from-[#D97706] to-[#F59E0B] p-2.5 rounded-xl shadow-md text-white">
                                <Bell className="w-6 h-6" />
                            </span>
                            Notifications
                        </h1>
                        <p className="text-gray-500 mt-2 ml-1 text-sm">
                            Manage your alerts and order updates
                        </p>
                    </div>

                    <div className="flex items-center gap-3 bg-white p-1.5 rounded-xl shadow-sm border border-gray-100 w-fit">
                        <button
                            onClick={() => setFilter('all')}
                            className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${filter === 'all' ? 'bg-[#D97706] text-white shadow-sm' : 'text-gray-600 hover:bg-gray-50'}`}
                        >
                            All
                        </button>
                        <button
                            onClick={() => setFilter('unread')}
                            className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${filter === 'unread' ? 'bg-[#D97706] text-white shadow-sm' : 'text-gray-600 hover:bg-gray-50'}`}
                        >
                            Unread
                        </button>
                    </div>
                </div>

                {/* Content Area */}
                <div className="bg-white rounded-3xl border border-gray-100 shadow-[0_2px_20px_rgba(0,0,0,0.02)] min-h-[500px] p-6 md:p-8 relative">

                    {/* Clear All Button - Top Right Absolute */}
                    {notifications.length > 0 && (
                        <div className="absolute top-6 right-6 z-10">
                            <button
                                onClick={clearAll}
                                className="group flex items-center gap-2 text-xs font-semibold text-gray-400 hover:text-red-600 transition-colors px-3 py-1.5 rounded-full hover:bg-red-50"
                            >
                                <Trash2 className="w-3.5 h-3.5 group-hover:scale-110 transition-transform" />
                                Clear History
                            </button>
                        </div>
                    )}

                    {loading ? (
                        <div className="space-y-8 animate-pulse">
                            {[1, 2].map(i => (
                                <div key={i}>
                                    <div className="h-4 w-24 bg-gray-100 rounded mb-4" />
                                    <div className="space-y-3">
                                        <div className="h-24 bg-gray-50 rounded-2xl" />
                                        <div className="h-24 bg-gray-50 rounded-2xl" />
                                    </div>
                                </div>
                            ))}
                        </div>
                    ) : filteredNotifications.length === 0 ? (
                        <div className="h-full flex flex-col items-center justify-center py-20">
                            <div className="w-24 h-24 bg-[#FAFAF7] rounded-full flex items-center justify-center mb-6">
                                <div className="w-16 h-16 bg-[#D97706]/10 rounded-full flex items-center justify-center animate-pulse">
                                    <Bell className="w-8 h-8 text-[#D97706]" />
                                </div>
                            </div>
                            <h3 className="text-xl font-bold text-[#111827]">All caught up!</h3>
                            <p className="text-gray-400 mt-2 max-w-xs text-center">
                                {filter === 'unread' ? "You have no unread notifications." : "You have no notifications at the moment."}
                            </p>
                            {filter === 'unread' && (
                                <button
                                    onClick={() => setFilter('all')}
                                    className="mt-6 text-[#D97706] font-medium hover:underline text-sm"
                                >
                                    View all notifications
                                </button>
                            )}
                        </div>
                    ) : (
                        <div className="space-y-10">
                            {groupOrder.map(group => {
                                const groupItems = groupedNotifications[group];
                                if (!groupItems || groupItems.length === 0) return null;

                                return (
                                    <div key={group}>
                                        <h3 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                                            <Calendar className="w-3.5 h-3.5" />
                                            {group}
                                        </h3>
                                        <div className="space-y-3">
                                            <AnimatePresence>
                                                {groupItems.map((notif) => (
                                                    <motion.div
                                                        key={notif._id}
                                                        initial={{ opacity: 0, x: -10 }}
                                                        animate={{ opacity: 1, x: 0 }}
                                                        exit={{ opacity: 0, height: 0, marginBottom: 0 }}
                                                        layout
                                                        className={`group relative overflow-hidden rounded-2xl border transition-all duration-300 ${notif.isRead
                                                            ? 'bg-white border-gray-100 hover:border-gray-200'
                                                            : 'bg-[#FFFCF5] border-[#D97706]/20 shadow-sm'
                                                            }`}
                                                    >
                                                        {/* Unread Indicator Bar */}
                                                        {!notif.isRead && (
                                                            <div className="absolute left-0 top-0 bottom-0 w-1 bg-[#D97706]" />
                                                        )}

                                                        <div className="p-5 flex gap-5">
                                                            {/* Icon Box */}
                                                            <div className={`flex-shrink-0 w-12 h-12 rounded-xl flex items-center justify-center ${notif.isRead ? 'bg-gray-50' : 'bg-white shadow-sm border border-[#D97706]/10'
                                                                }`}>
                                                                {getIcon(notif.type)}
                                                            </div>

                                                            <div className="flex-1 min-w-0">
                                                                <div className="flex justify-between items-start mb-1">
                                                                    <h3 className={`font-semibold text-base pr-8 ${notif.isRead ? 'text-gray-700' : 'text-[#111827]'}`}>
                                                                        {notif.title}
                                                                    </h3>
                                                                    <span className="text-[11px] text-gray-400 font-medium whitespace-nowrap bg-gray-50 px-2 py-1 rounded-full">
                                                                        {format(new Date(notif.createdAt), 'h:mm a')}
                                                                    </span>
                                                                </div>

                                                                <p className={`text-sm leading-relaxed ${notif.isRead ? 'text-gray-500' : 'text-gray-700'}`}>
                                                                    {notif.message}
                                                                </p>

                                                                {/* Action Link Example - Subscription */}
                                                                {notif.metadata?.subscriptionId && (
                                                                    <div className="mt-3">
                                                                        <Link
                                                                            href="/profile?tab=subscriptions"
                                                                            className="inline-flex items-center gap-1.5 text-xs font-semibold text-[#D97706] hover:text-[#B45309] bg-[#D97706]/5 hover:bg-[#D97706]/10 px-3 py-1.5 rounded-lg transition-colors"
                                                                        >
                                                                            View Subscription <ArrowRight className="w-3 h-3" />
                                                                        </Link>
                                                                    </div>
                                                                )}
                                                            </div>
                                                        </div>

                                                        {/* Hover Actions */}
                                                        <div className="absolute top-4 right-4 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity bg-white/80 backdrop-blur-sm p-1 rounded-lg shadow-sm border border-gray-100">
                                                            {!notif.isRead && (
                                                                <button
                                                                    onClick={() => markAsRead(notif._id)}
                                                                    className="p-1.5 text-gray-400 hover:text-[#D97706] rounded-md hover:bg-[#D97706]/5 transition-colors"
                                                                    title="Mark as read"
                                                                >
                                                                    <Check className="w-4 h-4" />
                                                                </button>
                                                            )}
                                                            <button
                                                                onClick={() => deleteNotification(notif._id)}
                                                                className="p-1.5 text-gray-400 hover:text-red-500 rounded-md hover:bg-red-50 transition-colors"
                                                                title="Delete"
                                                            >
                                                                <Trash2 className="w-4 h-4" />
                                                            </button>
                                                        </div>
                                                    </motion.div>
                                                ))}
                                            </AnimatePresence>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </div>
            </main>
            <Footer />
        </div>
    );
}

function ArrowRight({ className }: { className?: string }) {
    return (
        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}>
            <path d="M5 12h14" />
            <path d="m12 5 7 7-7 7" />
        </svg>
    );
}

'use client';

import { useEffect, useState } from 'react';
import Link from 'next/link';
import Image from 'next/image';
import Header from '@/components/Header';
import Footer from '@/components/Footer';
import { Order } from '@/lib/types/checkout';
import {
  CheckCircle2,
  MapPin,
  CreditCard,
  Download,
  Package,
  Truck,
  ShieldCheck,
  ChevronRight,
  Gift,
  Star,
  Clock,
  Home,
  Phone,
  Receipt
} from 'lucide-react';
import { generateInvoice } from '@/lib/utils/invoice-generator';
import { motion, AnimatePresence } from 'framer-motion';
import { getOrderSession } from '@/app/actions/session';

const API_BASE = process.env.NEXT_PUBLIC_API_BASE_URL;
type PaymentMethodKey = 'cod' | 'upi' | 'card' | 'netbanking';

const OrderConfirmationPage = () => {
  const [order, setOrder] = useState<Order | null>(null);
  const [loading, setLoading] = useState(true);

  // ----------------------------------------------------------------------
  // 📥 Load Order Logic
  // ----------------------------------------------------------------------
  useEffect(() => {
    async function loadOrder() {
      try {
        const { lastOrderId, lastOrder } = await getOrderSession();
        
        if (lastOrder) {
          setOrder(lastOrder);
          setLoading(false);
          return;
        }

        const storedUserId = localStorage.getItem("userId"); // Could potentially move this to AuthSession too if needed, but lastOrderId is the main part. Let's just use it or auth fetch if available.
        if (!lastOrderId) {
          setLoading(false);
          return;
        }

        // If we have an ID but no full order object, fetch it
        // We will just use the API if needed.
        const apiUrl = `${API_BASE}/api/order?id=${lastOrderId}${storedUserId ? `&userId=${storedUserId}` : ''}`;
        const response = await fetch(apiUrl);
        const data = await response.json();
        if (data?.success && data.order) {
          setOrder(data.order);
        }
      } catch (error) {
        console.error("Error loading order:", error);
      } finally {
        setLoading(false);
      }
    }
    loadOrder();
  }, []);

  // ----------------------------------------------------------------------
  // 🛠️ Helpers
  // ----------------------------------------------------------------------
  const handleDownloadInvoice = () => {
    if (!order) return;
    try { generateInvoice(order); } catch (err) { console.error(err); }
  };

  const resolveImage = (image?: string) => {
    if (!image) return "/images/placeholder.png";
    const cleanImage = image.trim();
    if (cleanImage.startsWith("http") || cleanImage.startsWith("data:")) return cleanImage;
    // Local images are in /images/products/
    return `/images/products/${cleanImage.replace(/^\/+/, "").replace(/^images\/products\//, "")}`;
  };

  const paymentMethodNames: Record<PaymentMethodKey, string> = {
    cod: 'Cash on Delivery',
    upi: 'UPI Payment',
    card: 'Credit/Debit Card',
    netbanking: 'Net Banking',
  };

  // ----------------------------------------------------------------------
  // 🔄 Loading State
  // ----------------------------------------------------------------------
  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col">
        <Header />
        <div className="flex-1 flex flex-col items-center justify-center p-4">
          <div className="w-12 h-12 border-4 border-amber-500 border-t-transparent rounded-full animate-spin mb-4" />
          <p className="text-gray-500 font-medium animate-pulse">Fetching your order...</p>
        </div>
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // ❌ Error State
  // ----------------------------------------------------------------------
  if (!order) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col">
        <Header />
        <div className="flex-1 flex flex-col items-center justify-center p-4 text-center">
          <div className="w-20 h-20 bg-gray-200 rounded-full flex items-center justify-center mb-4">
            <Package className="text-gray-400" size={32} />
          </div>
          <h2 className="text-xl font-bold text-gray-800 mb-2">Order Not Found</h2>
          <p className="text-gray-500 mb-6 max-w-xs mx-auto">We couldn't retrieve the order details. Please check your orders page.</p>
          <Link href="/products" className="bg-amber-600 text-white px-6 py-3 rounded-lg font-semibold hover:bg-amber-700 transition-colors">
            Continue Shopping
          </Link>
        </div>
        <Footer />
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // 🎨 Main UI (Professional E-Commerce)
  // ----------------------------------------------------------------------
  return (
    <div className="min-h-screen bg-[#F1F3F6] font-sans text-gray-900">
      <Header />

      {/* 🟢 Status Strip (Amazon/Flipkart Style) */}
      <div className="bg-white border-b border-gray-200 sticky top-20 z-30 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 lg:px-6 py-4 flex flex-col sm:flex-row items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <motion.div
              initial={{ scale: 0 }} animate={{ scale: 1 }}
              className="w-8 h-8 bg-amber-400 rounded-full flex items-center justify-center text-white shadow-sm"
            >
              <CheckCircle2 size={18} strokeWidth={3} />
            </motion.div>
            <div>
              <h1 className="text-lg font-bold text-gray-800 leading-tight">Order Placed Successfully</h1>
              <p className="text-xs text-gray-500 font-medium">Order ID: <span className="font-mono text-gray-700">#{order.orderNumber}</span></p>
            </div>
          </div>

          <div className="flex items-center gap-3">
            {/* <button onClick={handleDownloadInvoice} className="hidden sm:flex items-center gap-2 text-sm font-semibold text-blue-600 hover:bg-blue-50 px-3 py-1.5 rounded-md transition-colors border border-transparent hover:border-blue-100">
              <Receipt size={16} />
              Invoice
            </button> */}
            <Link href="/products" className="bg-amber-500 text-white text-sm font-bold px-5 py-2 rounded shadow-sm hover:shadow-md hover:bg-amber-600 transition-all">
              Continue Shopping
            </Link>
          </div>
        </div>
      </div>

      <main className="max-w-7xl mx-auto px-4 lg:px-6 py-6 lg:py-8">
        <div className="grid lg:grid-cols-12 gap-6">

          {/* ------------------------------------------------------- */}
          {/* LEFT COLUMN (Timeline, Rewards, Items) - Span 8 */}
          {/* ------------------------------------------------------- */}
          <div className="lg:col-span-8 space-y-5">

            {/* 🚚 1. Delivery & Timeline Card */}
            <motion.div
              initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}
              className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden"
            >
              <div className="p-6 border-b border-gray-100 bg-gradient-to-r from-blue-50 to-white">
                <div className="flex items-start gap-4">
                  <div className="bg-blue-100 p-3 rounded-full text-blue-600 mt-1">
                    <Truck size={24} />
                  </div>
                  <div>
                    <h2 className="text-xl font-bold text-gray-900">Arriving by Thu, 16 Jan</h2>
                    <p className="text-sm text-gray-600 mt-1">Super fast delivery activated. We're packing your order now!</p>
                  </div>
                </div>
              </div>

              {/* Timeline */}
              <div className="p-6 pt-8">
                <div className="relative">
                  {/* Mobile Vertical Line */}
                  <div className="absolute top-0 bottom-0 left-[19px] w-0.5 bg-gray-200 md:hidden" />
                  {/* Desktop Horizontal Line */}
                  <div className="hidden md:block absolute top-[14px] left-0 right-0 h-1 bg-gray-100 rounded-full" />
                  <div className="hidden md:block absolute top-[14px] left-0 w-1/3 h-1 bg-amber-500 rounded-full" />

                  <div className="flex flex-col md:flex-row justify-between gap-6 md:gap-0 relative">
                    {[
                      { title: "Order Placed", date: "Today, 2:30 PM", active: true },
                      { title: "Packed", date: "Tomorrow", active: false },
                      { title: "Shipped", date: "Fri, 14 Jan", active: false },
                      { title: "Out for Delivery", date: "Thu, 16 Jan", active: false },
                    ].map((step, idx) => (
                      <div key={idx} className="flex md:flex-col items-center md:items-center gap-4 md:gap-3 relative z-10 md:w-1/4">
                        <div className={`w-10 h-10 md:w-8 md:h-8 rounded-full border-[3px] flex items-center justify-center bg-white ${step.active ? 'border-amber-500' : 'border-gray-200'}`}>
                          {step.active && <div className="w-3 h-3 md:w-2.5 md:h-2.5 bg-amber-500 rounded-full" />}
                        </div>
                        <div className="md:text-center pt-2 md:pt-0">
                          <p className={`text-sm font-bold ${step.active ? 'text-gray-900' : 'text-gray-400'}`}>{step.title}</p>
                          <p className="text-xs text-gray-500 mt-0.5">{step.date}</p>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            </motion.div>

            {/* 🎁 2. Reward / Scratch Card (Blinkit Style) */}
            <motion.div
              initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.1 }}
              className="bg-gradient-to-r from-amber-500 via-orange-500 to-red-500 rounded-lg shadow-md p-0.5 text-white relative overflow-hidden group cursor-pointer"
            >
              <div className="bg-white/10 backdrop-blur-sm p-4 sm:p-5 flex items-center justify-between relative z-10 hover:bg-white/15 transition-colors rounded-[inherit]">
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-lg text-amber-500">
                    <Gift size={24} className="animate-bounce" />
                  </div>
                  <div>
                    <p className="font-bold text-lg leading-tight">You've unlocked a Mystery Reward!</p>
                    <p className="text-amber-100 text-xs sm:text-sm">Claim it on your next order above ₹500</p>
                  </div>
                </div>
                <ChevronRight className="text-white/80 group-hover:translate-x-1 transition-transform" />
              </div>
              {/* Shine Effect */}
              <div className="absolute top-0 -inset-full h-full w-1/2 z-5 block transform -skew-x-12 bg-gradient-to-r from-transparent to-white opacity-20 group-hover:animate-shine" />
            </motion.div>

            {/* 📦 3. Items List */}
            <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden">
              <div className="px-6 py-4 border-b border-gray-100 flex items-center justify-between bg-gray-50/50">
                <h3 className="font-bold text-gray-800 flex items-center gap-2">
                  <Package size={18} className="text-gray-500" />
                  Items in this Order ({order.items.length})
                </h3>
              </div>
              <div className="divide-y divide-gray-100">
                {order.items.map((item, idx) => {
                  // Robust Data Extraction
                  const name = item.productName || (item as any).product?.name || (item as any).name || (item as any).title || "Product Name Unavailable";
                  const image = item.image || (item as any).product?.image || "/images/placeholder.png";
                  const price = item.price ?? (item as any).unitPrice ?? (item as any).product?.price ?? 0;
                  const qty = item.quantity || (item as any).qty || 1;
                  const itemTotal = qty * price;

                  const finalImage = resolveImage(image);

                  return (
                    <div key={idx} className="p-4 sm:p-5 flex gap-4 sm:gap-6 hover:bg-gray-50/50 transition-colors">
                      <div className="w-24 h-24 bg-white border border-gray-200 rounded-md p-2 relative flex-shrink-0">
                        <Image
                          src={finalImage}
                          alt={name}
                          fill
                          className="object-contain"
                          unoptimized={finalImage.startsWith("http")}
                        />
                      </div>
                      {/* DEBUG: Show filtered image path */}
                      <p className="hidden text-[10px] text-red-500 absolute bottom-0 bg-white/80 p-0.5 z-10">{finalImage}</p>

                      <div className="flex-1 min-w-0">
                        <Link href={(item as any).productId ? `/product/${(item as any).productId}` : (item as any).product?._id ? `/product/${(item as any).product._id}` : '#'} className="text-base font-semibold text-gray-900 hover:text-amber-600 line-clamp-2 transition-colors">
                          {name}
                        </Link>
                        <p className="text-sm text-gray-500 mt-1">Unit Price: ₹{price.toFixed(2)}</p>
                        <p className="text-sm text-gray-500">Qty: <span className="font-semibold text-gray-800">{qty}</span></p>
                        <p className="font-bold text-lg text-gray-900 mt-2">₹{itemTotal.toFixed(2)}</p>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>

            {/* 📍 4. Delivery Address */}
            <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6 flex flex-col sm:flex-row gap-6">
              <div className="flex-1">
                <h3 className="font-bold text-gray-800 mb-3 flex items-center gap-2">
                  <MapPin size={18} className="text-gray-400" />
                  Shipping Details
                </h3>
                <div className="pl-6">
                  <p className="font-bold text-gray-900">{order.shippingAddress.fullName}</p>
                  <p className="text-sm text-gray-600 mt-1 leading-relaxed">
                    {order.shippingAddress.addressLine1}, {order.shippingAddress.addressLine2} <br />
                    {order.shippingAddress.city}, {order.shippingAddress.state} - {order.shippingAddress.pincode}
                  </p>
                  <div className="flex items-center gap-2 mt-3 text-sm text-gray-600">
                    <Phone size={14} />
                    <span>{order.shippingAddress.phone}</span>
                  </div>
                </div>
              </div>
              {/* Visual Map Placeholder (Aesthetic Touch) */}
              <div className="w-full sm:w-48 h-32 bg-amber-50 rounded-lg border border-amber-100 flex items-center justify-center relative overflow-hidden">
                <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]"></div>
                <MapPin className="text-amber-300 w-12 h-12" />
              </div>
            </div>

          </div>

          {/* ------------------------------------------------------- */}
          {/* RIGHT COLUMN (Summary) - Span 4 */}
          {/* ------------------------------------------------------- */}
          <div className="lg:col-span-4 space-y-5">

            {/* Price Breakdown */}
            <div className="bg-white rounded-lg shadow-sm border border-gray-200 sticky top-28">
              {/* Price Breakdown */}
              <div className="bg-white rounded-lg shadow-sm border border-gray-200 sticky top-28">
                <div className="px-5 py-4 border-b border-gray-100">
                  <h3 className="font-bold text-gray-800">Price Details</h3>
                </div>
                <div className="p-5 space-y-3">
                  {(() => {
                    // ----------------------------------------------------------------------
                    // 🧮 CLIENT-SIDE RECALCULATION FOR CONSISTENCY
                    // This ensures that what the user sees is mathematically correct (A+B+C = Total)
                    // preventing mismatch between backend 'total' and frontend calculated components.
                    // ----------------------------------------------------------------------
                    const platformFee = 5;

                    // 1. Calculate Subtotal from Items
                    const calculatedSubtotal = order.items.reduce((acc, item) => {
                      const price = item.price ?? (item as any).unitPrice ?? (item as any).product?.price ?? 0;
                      const qty = item.quantity || (item as any).qty || 1;
                      return acc + (price * qty);
                    }, 0);

                    // 2. Shipping Logic (consistent with Checkout)
                    const dbShipping = order.shipping ?? (order as any).shippingCharges;
                    const calculatedShipping = dbShipping !== undefined
                      ? dbShipping
                      : (calculatedSubtotal >= 500 ? 0 : 20);

                    // 3. Discount (from DB)
                    const discountVal = order.discount || (order as any).discounts || 0;

                    // 4. Tax (18% of Taxable Value)
                    const taxableAmount = Math.max(0, calculatedSubtotal - discountVal);
                    const calculatedTax = taxableAmount * 0.18;

                    // 5. Final Total
                    const calculatedTotal = calculatedSubtotal - discountVal + calculatedTax + calculatedShipping + platformFee;

                    return (
                      <>
                        <div className="flex justify-between text-sm text-gray-600">
                          <span>Price ({order.items.length} items)</span>
                          <span>₹{calculatedSubtotal.toFixed(2)}</span>
                        </div>
                        {discountVal > 0 && (
                          <div className="flex justify-between text-sm text-green-600">
                            <span>Discount</span>
                            <span>- ₹{discountVal.toFixed(2)}</span>
                          </div>
                        )}
                        <div className="flex justify-between text-sm text-gray-600">
                          <span>Platform Fee</span>
                          <span>₹{platformFee.toFixed(2)}</span>
                        </div>
                        <div className="flex justify-between text-sm text-gray-600">
                          <span>Delivery Charges</span>
                          <span className={calculatedShipping === 0 ? "text-green-600 uppercase text-xs font-bold" : ""}>
                            {calculatedShipping === 0 ? 'FREE' : `₹${calculatedShipping.toFixed(2)}`}
                          </span>
                        </div>
                        <div className="flex justify-between text-sm text-gray-600">
                          <span>Tax (18% GST)</span>
                          <span>₹{calculatedTax.toFixed(2)}</span>
                        </div>

                        <div className="p-5 pt-0 -mx-5 pb-0"> {/* Negative margin to break out of padding then re-add */}
                          <div className="border-t border-dashed border-gray-200 pt-4 mb-4">
                            <div className="flex justify-between items-center px-5">
                              <span className="font-bold text-lg text-gray-900">Total Amount</span>
                              <span className="font-bold text-xl text-gray-900">₹{calculatedTotal.toFixed(2)}</span>
                            </div>
                          </div>
                        </div>
                      </>
                    );
                  })()}
                </div>

                <div className="flex items-center gap-3 bg-gray-50 p-3 rounded-md border border-gray-100 text-sm text-gray-600 mb-4">
                  <CreditCard size={16} />
                  <span>Payment via <b>{
                    (() => {
                      // Fix: Check order.payment.method (DB structure) OR order.paymentMethod (Frontend structure)
                      const method = (order as any).payment?.method || order.paymentMethod;
                      const normalizedMethod = method?.toLowerCase();

                      const names: Record<string, string> = {
                        cod: 'Cash on Delivery',
                        upi: 'UPI Payment',
                        card: 'Credit/Debit Card',
                        netbanking: 'Net Banking'
                      };
                      return names[normalizedMethod] || method || 'Unknown Method';
                    })()
                  }</b></span>
                </div>

                <button
                  onClick={handleDownloadInvoice}
                  className="w-full flex items-center justify-center gap-2 bg-white border border-gray-200 hover:bg-gray-50 text-gray-700 font-semibold py-3 rounded-lg transition-all text-sm mb-2"
                >
                  <Download size={16} />
                  Download Invoice
                </button>
              </div>
            </div>
          </div>

        </div>
      </main>
      <Footer />
    </div>
  );
};

export default OrderConfirmationPage;

'use client';

import React, { useEffect, useState } from 'react';
import { useAuth } from '@/lib/context/AuthContext';
import { useParams, useRouter } from 'next/navigation';
import { ChevronLeft, Package, Clock, MapPin, Phone, Star, ShieldCheck, Truck, Maximize2, Minimize2 } from 'lucide-react';
import OrderTrackingMap from '@/components/orders/OrderTrackingMap';
import Header from '@/components/Header';
import { motion, AnimatePresence } from 'framer-motion';

const API_BASE = process.env.NEXT_PUBLIC_API_BASE_URL || "http://horeca-backend-six.vercel.app";

const OrderDetailsPage = () => {
    const { id } = useParams();
    const { token } = useAuth();
    const router = useRouter();
    const [order, setOrder] = useState<any>(null);
    const [loading, setLoading] = useState(true);
    const [isFullScreen, setIsFullScreen] = useState(false);

    // Trigger resize event when toggling full screen to ensure map renders correctly
    useEffect(() => {
        const handleResize = () => {
            window.dispatchEvent(new Event('resize'));
        };
        // Small delay to allow transition to start/finish
        const timeout = setTimeout(handleResize, 100);
        const timeout2 = setTimeout(handleResize, 550); // After transition
        return () => {
            clearTimeout(timeout);
            clearTimeout(timeout2);
        };
    }, [isFullScreen]);

    useEffect(() => {
        if (!id || !token) return;

        const fetchOrder = async () => {
            try {
                const res = await fetch(`${API_BASE}/api/order?id=${id}`, {
                    headers: {
                        Authorization: `Bearer ${token}`
                    }
                });
                const data = await res.json();
                if (data.success) {
                    setOrder(data.order);
                }
            } catch (err) {
                console.error("Failed to fetch order", err);
            } finally {
                setLoading(false);
            }
        };

        fetchOrder();
    }, [id, token]);

    if (loading) return (
        <div className="min-h-screen flex items-center justify-center bg-gray-50">
            <motion.div
                animate={{ rotate: 360 }}
                transition={{ duration: 1, repeat: Infinity, ease: "linear" }}
                className="w-12 h-12 border-4 border-orange-500 border-t-transparent rounded-full"
            />
        </div>
    );

    if (!order) return <div className="p-10 text-center text-gray-500">Order not found</div>;

    const isTrackingAvailable = ['out_for_delivery', 'shipped', 'delivered'].includes(order.status);

    const destination = {
        lat: order.shippingAddress?.lat || 28.6139,
        lng: order.shippingAddress?.lng || 77.2090,
        address: order.shippingAddress?.addressLine1
    };

    const steps = [
        { key: 'placed', label: 'Placed', icon: Package },
        { key: 'shipped', label: 'Shipped', icon: Truck },
        { key: 'out_for_delivery', label: 'Out for Delivery', icon: Clock },
        { key: 'delivered', label: 'Delivered', icon: ShieldCheck },
    ];

    const currentStepIndex = steps.findIndex(s => s.key === order.status) !== -1
        ? steps.findIndex(s => s.key === order.status)
        : order.status === 'cancelled' ? -1 : 0;



    return (
        <div className="min-h-screen bg-gray-50 relative overflow-hidden">
            {!isFullScreen && (
                <div className="fixed top-0 left-0 right-0 z-30">
                    <Header />
                </div>
            )}

            {/* IMMERSIVE MAP BACKGROUND */}
            <div
                className={`transition-all duration-500 ease-in-out z-0 ${isFullScreen
                    ? 'fixed inset-0 h-[100dvh] w-screen'
                    : 'absolute top-0 left-0 right-0 h-[55vh]'
                    }`}
            >
                {isTrackingAvailable ? (
                    <OrderTrackingMap destination={destination} status={order.status} />
                ) : (
                    <div className="w-full h-full bg-orange-50 flex items-center justify-center">
                        <div className="text-center opacity-50">
                            <Package size={64} className="mx-auto mb-2 text-orange-300" />
                            <p className="font-medium text-orange-800">Map view unavailable for this status</p>
                        </div>
                    </div>
                )}
            </div>

            {/* HEADER CONTROLS */}
            <div className={`fixed left-0 right-0 z-20 p-4 flex items-center justify-between pointer-events-none transition-all duration-300 ${isFullScreen ? 'top-0' : 'top-36'}`}>
                <motion.button
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                    onClick={() => router.back()}
                    className="w-10 h-10 bg-white/80 backdrop-blur-md rounded-full flex items-center justify-center shadow-lg border border-white/50 text-gray-700 hover:bg-white pointer-events-auto transition-colors"
                >
                    <ChevronLeft size={24} />
                </motion.button>
                <div className="flex gap-3">
                    <motion.div
                        initial={{ opacity: 0, y: -20 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="bg-white/80 backdrop-blur-md px-4 py-1.5 rounded-full shadow-lg border border-white/50 text-xs font-bold text-gray-800 pointer-events-auto"
                    >
                        Order #{order.orderNumber}
                    </motion.div>

                    {/* Full Screen Toggle */}
                    {isTrackingAvailable && (
                        <motion.button
                            initial={{ opacity: 0, scale: 0.8 }}
                            animate={{ opacity: 1, scale: 1 }}
                            onClick={() => setIsFullScreen(!isFullScreen)}
                            className="w-10 h-10 bg-white/80 backdrop-blur-md rounded-full flex items-center justify-center shadow-lg border border-white/50 text-gray-700 hover:bg-white pointer-events-auto transition-colors"
                        >
                            {isFullScreen ? <Minimize2 size={20} /> : <Maximize2 size={20} />}
                        </motion.button>
                    )}
                </div>
            </div>

            {/* FLOATING CONTENT SHEET */}
            <AnimatePresence>
                {!isFullScreen && (
                    <motion.div
                        initial={{ y: "100%" }}
                        animate={{ y: 0 }}
                        exit={{ y: "100%" }}
                        transition={{ type: "spring", stiffness: 100, damping: 20 }}
                        className="absolute top-[45vh] left-0 right-0 bottom-0 z-10 flex flex-col items-center pointer-events-none"
                    >
                        <div className="w-full max-w-2xl h-full flex flex-col pointer-events-auto">
                            <div className="flex-1 bg-white rounded-t-[2.5rem] shadow-[0_-10px_40px_-10px_rgba(0,0,0,0.1)] overflow-y-auto relative no-scrollbar">

                                {/* Floating Status Icon */}
                                <div className="sticky top-0 z-20 mt-10">
                                    <div className="absolute -top-10 left-1/2 -translate-x-1/2">
                                        <motion.div
                                            initial={{ scale: 0 }}
                                            animate={{ scale: 1 }}
                                            transition={{ delay: 0.4, type: "spring" }}
                                            className="bg-orange-500 text-white p-4 rounded-full shadow-xl shadow-orange-500/30 border-4 border-white"
                                        >
                                            {order.status === 'delivered' ? <ShieldCheck size={32} /> :
                                                order.status === 'out_for_delivery' ? <Truck size={32} /> :
                                                    <Clock size={32} />}
                                        </motion.div>
                                    </div>
                                </div>

                                <div className="pt-12 pb-20 px-6 sm:px-8 space-y-8">

                                    {/* Status Headline */}
                                    <div className="text-center">
                                        <h2 className="text-2xl font-bold text-gray-900">
                                            {order.status === 'out_for_delivery' ? 'Arriving Soon!' :
                                                order.status === 'delivered' ? 'Order Delivered' :
                                                    order.status.replace(/_/g, ' ')}
                                        </h2>
                                        <p className="text-gray-500 mt-1">
                                            {order.status === 'out_for_delivery' ? 'Your order is on the way to your location.' :
                                                `Updated on ${new Date(order.updatedAt).toLocaleTimeString()}`}
                                        </p>
                                    </div>

                                    {/* Progress Stepper */}
                                    <div className="flex justify-between items-center relative px-2">
                                        {/* Connecting Line */}
                                        <div className="absolute left-0 right-0 top-1/2 -translate-y-1/2 h-1 bg-gray-100 -z-10 rounded-full mx-4" />
                                        <div
                                            className="absolute left-0 h-1 bg-orange-500 -z-10 rounded-full mx-4 transition-all duration-1000"
                                            style={{ width: `${(currentStepIndex / (steps.length - 1)) * 100}%` }}
                                        />

                                        {steps.map((step, idx) => {
                                            const isCompleted = idx <= currentStepIndex;
                                            const isCurrent = idx === currentStepIndex;
                                            const Icon = step.icon;

                                            return (
                                                <div key={step.key} className="flex flex-col items-center gap-2">
                                                    <motion.div
                                                        initial={false}
                                                        animate={{
                                                            scale: isCurrent ? 1.2 : 1,
                                                            backgroundColor: isCompleted ? '#F97316' : '#F3F4F6'
                                                        }}
                                                        className={`w-10 h-10 rounded-full flex items-center justify-center border-4 border-white shadow-sm z-10 transition-colors duration-300`}
                                                    >
                                                        <Icon size={16} className={isCompleted ? 'text-white' : 'text-gray-400'} />
                                                    </motion.div>
                                                    <span className={`text-[10px] font-bold uppercase tracking-wider ${isCompleted ? 'text-orange-600' : 'text-gray-400'}`}>
                                                        {step.label}
                                                    </span>
                                                </div>
                                            );
                                        })}
                                    </div>

                                    {/* Driver Info Card (Only if out_for_delivery) */}
                                    {order.status === 'out_for_delivery' && (
                                        <motion.div
                                            initial={{ opacity: 0, y: 20 }}
                                            animate={{ opacity: 1, y: 0 }}
                                            className="bg-orange-50 p-4 rounded-2xl flex items-center justify-between border border-orange-100"
                                        >
                                            <div className="flex items-center gap-3">
                                                <div className="w-12 h-12 bg-orange-200 rounded-full flex items-center justify-center overflow-hidden border-2 border-white">
                                                    <span className="text-xl">👨‍✈️</span>
                                                </div>
                                                <div>
                                                    <h3 className="font-bold text-gray-900">John Delivery</h3>
                                                    <div className="flex items-center gap-1 text-xs text-orange-700 font-medium">
                                                        <Star size={12} className="fill-orange-500 stroke-orange-500" /> 4.8 Rating
                                                    </div>
                                                </div>
                                            </div>
                                            <button className="w-10 h-10 bg-green-500 rounded-full flex items-center justify-center text-white shadow-lg shadow-green-200 hover:bg-green-600 transition-colors">
                                                <Phone size={18} />
                                            </button>
                                        </motion.div>
                                    )}

                                    {/* Order Items */}
                                    <div>
                                        <h3 className="font-bold text-gray-900 mb-4 flex items-center gap-2">
                                            <Package size={18} className="text-orange-500" /> Order Items
                                        </h3>
                                        <div className="space-y-4">
                                            {order.items.map((item: any, i: number) => (
                                                <motion.div
                                                    key={i}
                                                    initial={{ opacity: 0, x: -10 }}
                                                    animate={{ opacity: 1, x: 0 }}
                                                    transition={{ delay: 0.5 + (i * 0.1) }}
                                                    className="flex gap-4 p-3 bg-gray-50 rounded-xl hover:bg-gray-100 transition-colors"
                                                >
                                                    <div className="w-16 h-16 bg-white rounded-lg flex-shrink-0 relative overflow-hidden shadow-sm border border-gray-200">
                                                        {item.image ? (
                                                            <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
                                                        ) : (
                                                            <div className="flex items-center justify-center h-full text-gray-400">📦</div>
                                                        )}
                                                    </div>
                                                    <div className="flex-1 flex flex-col justify-center">
                                                        <p className="font-bold text-gray-800 line-clamp-1">{item.productName || item.name}</p>
                                                        <p className="text-xs text-gray-500 font-medium bg-white px-2 py-0.5 rounded-md inline-block w-fit mt-1 border border-gray-200">
                                                            Qty: {item.quantity}
                                                        </p>
                                                    </div>
                                                    <div className="flex flex-col justify-center text-right">
                                                        <p className="font-bold text-gray-900">₹{((item.unitPrice || 0) * (item.quantity || 0)).toFixed(2)}</p>
                                                    </div>
                                                </motion.div>
                                            ))}
                                        </div>
                                        <div className="mt-6 flex justify-between items-center p-4 bg-gray-900 text-white rounded-xl shadow-lg">
                                            <span className="font-medium text-gray-300">Total Amount</span>
                                            <span className="font-bold text-lg">₹{order.total}</span>
                                        </div>
                                    </div>

                                    {/* Delivery Address */}
                                    <div className="bg-white rounded-2xl">
                                        <h3 className="font-bold text-gray-900 mb-4 flex items-center gap-2">
                                            <MapPin size={18} className="text-orange-500" /> Delivery Address
                                        </h3>
                                        <div className="pl-2 border-l-2 border-dashed border-gray-200 ml-2">
                                            <div className="ml-4">
                                                <p className="font-bold text-gray-900">{order.shippingAddress?.fullName}</p>
                                                <p className="text-sm text-gray-500 mt-1 leading-relaxed">
                                                    {order.shippingAddress?.addressLine1}, {order.shippingAddress?.city}
                                                    <br />
                                                    {order.shippingAddress?.state} - {order.shippingAddress?.pincode}
                                                </p>
