'use client';

import React, { useEffect, useState } from 'react';
import { featuredProducts as fallbackFeatured } from '@/lib/data';
import { ArrowRight } from 'lucide-react';
import Link from 'next/link';
import ProductCard from './products/ProductCard';

// API Base URL
const API_URL = process.env.NEXT_PUBLIC_API_BASE_URL;

// ----------------------------------
// 🔧 Utility Functions
// ----------------------------------

function buildApiUrl(path: string) {
  const base = process.env.NEXT_PUBLIC_API_BASE_URL || "http://horeca-backend-six.vercel.app";
  return `${base.replace(/\/+$/, "")}/${path.replace(/^\/+/, "")}`.replace(/([^:]\/)\/+/g, "$1");
}

function normalizeImageSrc(img: any) {
  if (!img) return "/images/placeholder.png";
  const s = String(img).trim();
  if (!s) return "/images/placeholder.png";
  if (s.startsWith("http") || s.startsWith("//")) return s;
  return `/images/products/${s}`;
}

function mapRawToCard(raw: any) {
  if (!raw) return null;

  const id = raw._id ?? raw.id ?? raw.productId ?? null;
  const name = raw.name ?? "Unnamed product";
  const price = typeof raw.price === "number" ? raw.price : Number(raw.price ?? 0);

  let imageCandidate = "";
  if (Array.isArray(raw.images) && raw.images.length)
    imageCandidate = raw.images[0].url ?? raw.images[0];
  else if (typeof raw.image === "string") imageCandidate = raw.image;

  return {
    id: id ? String(id) : null,
    name,
    price,
    unit: raw.unit ?? "pcs",
    badge: raw.badge ?? (raw.isFeatured ? "Featured" : null),
    image: normalizeImageSrc(imageCandidate),
    inStock: typeof raw.inStock === 'boolean' ? raw.inStock : (typeof raw.stockQuantity === 'number' ? raw.stockQuantity > 0 : true),
    ...raw,
  };
}

// ----------------------------------
// ⭐ FEATURED PRODUCTS COMPONENT
// ----------------------------------

export default function FeaturedProducts() {
  const [items, setItems] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  // -------------------------------
  // 📌 LOAD FEATURED PRODUCTS
  // -------------------------------

  useEffect(() => {
    let mounted = true;

    (async () => {
      try {
        const url = buildApiUrl("api/products?featured=true&limit=8");
        const res = await fetch(url, { headers: { Accept: "application/json" } });

        if (!res.ok) throw new Error("Failed to load");

        const json = await res.json();
        let list: any[] = [];

        if (Array.isArray(json?.data?.items)) list = json.data.items;
        else if (Array.isArray(json?.data)) list = json.data;
        else if (Array.isArray(json)) list = json;
        else list = [];

        const mapped = list.map(mapRawToCard).filter(Boolean);

        if (mounted) setItems(mapped.length > 0 ? mapped : fallbackFeatured);
      } catch (err) {
        console.error("Featured fetch error", err);
        if (mounted) setItems(fallbackFeatured);
      } finally {
        if (mounted) setLoading(false);
      }
    })();

    return () => {
      mounted = false;
    };
  }, []);

  const displayed = items ?? [];

  return (
    <section className="py-20 bg-white">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">

        {/* Header */}
        <div className="flex justify-between items-end mb-10">
          <div>
            <h2 className="text-3xl font-bold text-[#111827]">Trending Near You</h2>
            <p className="text-gray-500 mt-1">Best deals on highly demanded products</p>
          </div>

          <Link
            href="/products"
            className="hidden lg:flex items-center gap-2 text-[#D97706] font-bold hover:text-[#B45309] transition-colors"
          >
            View All <ArrowRight size={20} />
          </Link>
        </div>

        {/* Products Grid */}
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-6 lg:gap-8">
          {loading
            ? Array.from({ length: 4 }).map((_, i) => (
              <div key={i} className="aspect-[3/4] bg-gray-100 rounded-2xl animate-pulse" />
            ))
            : displayed.map((product) => (
              <ProductCard key={product.id} product={product} />
            ))}
        </div>

        {/* Mobile View All */}
        <div className="text-center mt-12 lg:hidden">
          <Link
            href="/products"
            className="inline-flex items-center gap-2 bg-[#D97706] text-white px-8 py-4 rounded-full font-medium shadow-lg"
          >
            View All Products <ArrowRight size={18} />
          </Link>
        </div>
      </div>
    </section>
  );
}

"use client";

import { Search, Heart, ShoppingCart, User, Linkedin, Instagram, Facebook, Phone, Mail, X, Bell } from 'lucide-react';
import Link from 'next/link';
import Image from 'next/image';
import { useState, useEffect, useRef } from 'react';
import { useRouter } from 'next/navigation';
import CartButton from '@/components/cart/CartButton';
import LoginModal from '@/components/auth/LoginModal';
import { useAuth } from '@/lib/context/AuthContext';
import Fuse from 'fuse.js';

const API_BASE = process.env.NEXT_PUBLIC_API_BASE_URL;

export default function Header() {
  const [isLoginModalOpen, setIsLoginModalOpen] = useState(false);
  const [wishlistCount, setWishlistCount] = useState(0);
  const [wishlistLoading, setWishlistLoading] = useState(false);
  const { user, token, logout, isAuthenticated, isLoading } = useAuth();
  const [mounted, setMounted] = useState(false);
  const router = useRouter();

  // Search State
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<any[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const searchInputRef = useRef<HTMLInputElement>(null);
  const searchContainerRef = useRef<HTMLDivElement>(null);
  const debounceRef = useRef<NodeJS.Timeout | null>(null);

  // Ensure component is mounted to avoid hydration issues
  useEffect(() => {
    setMounted(true);
  }, []);

  // Fetch wishlist count when user is authenticated
  const [notificationCount, setNotificationCount] = useState(0);

  const fetchNotificationCount = async () => {
    if (!user?.id || !token) return;
    try {
      const res = await fetch(`${API_BASE}/api/notifications?userId=${user.id}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      const data = await res.json();
      if (data.success && Array.isArray(data.data)) {
        // Count unread
        const unread = data.data.filter((n: any) => !n.isRead).length;
        setNotificationCount(unread);
      }
    } catch (error) {
      console.error("Failed to fetch notifications", error);
    }
  };

  // Fetch wishlist and notifications when auth updates
  useEffect(() => {
    if (mounted && isAuthenticated && user?.id) {
      fetchWishlistCount();
      fetchNotificationCount();
    } else {
      setWishlistCount(0);
      setNotificationCount(0);
    }
  }, [mounted, isAuthenticated, user?.id]);

  // Listen for realtime wishlist updates
  useEffect(() => {
    const handleWishlistUpdate = () => {
      if (user?.id) fetchWishlistCount();
    };

    window.addEventListener('wishlist-updated', handleWishlistUpdate);
    return () => window.removeEventListener('wishlist-updated', handleWishlistUpdate);
  }, [user?.id]);

  const performSearch = async (query: string) => {
    if (!query.trim()) {
      setSearchResults([]);
      setIsSearching(false);
      return;
    }

    setIsSearching(true);
    try {
      const url = `${API_BASE || 'https://horeca-backend-six.vercel.app'}/api/products?q=${encodeURIComponent(query)}&limit=5`;
      const res = await fetch(url);
      const data = await res.json();

      if (data.success && Array.isArray(data.data?.items)) {
        setSearchResults(data.data.items);
      } else {
        setSearchResults([]);
      }
    } catch (error) {
      console.error("Search failed:", error);
      setSearchResults([]);
    } finally {
      setIsSearching(false);
    }
  };

  const handleSearch = (e: React.ChangeEvent<HTMLInputElement>) => {
    const query = e.target.value;
    setSearchQuery(query);

    if (debounceRef.current) clearTimeout(debounceRef.current);

    if (!query.trim()) {
      setSearchResults([]);
      return;
    }

    debounceRef.current = setTimeout(() => {
      performSearch(query);
    }, 300); // 300ms debounce
  };

  const fetchWishlistCount = async () => {
    if (!user?.id || !token) return;

    setWishlistLoading(true);
    try {
      const url = `${API_BASE}/api/wishlist?userId=${user.id}`;

      const response = await fetch(url, {
        method: "GET",
        headers: {
          Authorization: `Bearer ${token}`,
          Accept: "application/json",
        },
      });

      const data = await response.json();

      let count = 0;

      if (data?.data?.items) {
        count = data.data.items.length;
      } else if (data?.items) {
        count = data.items.length;
      }

      setWishlistCount(count);
    } catch (err) {
      console.error("🔥 Failed to fetch wishlist count:", err);
    } finally {
      setWishlistLoading(false);
    }
  };


  const formatPhoneNumber = (phone: string | undefined) => {
    if (!phone || typeof phone !== 'string' || phone.length < 10) {
      return '';
    }
    return `+91 ${phone.slice(0, 3)}***${phone.slice(6)}`;
  };

  const handleLogout = () => {
    logout();
    setWishlistCount(0);
  };

  const handleLoginClick = () => {
    setIsLoginModalOpen(true);
  };

  const toggleSearch = () => {
    setIsSearchOpen(!isSearchOpen);
    if (!isSearchOpen) {
      setSearchQuery('');
      setSearchResults([]);
    }
  };

  // Don't render user-specific content during SSR
  if (!mounted) {
    return (
      <header className="w-full bg-white">
        <div className="sticky top-0 z-50 bg-white/95 backdrop-blur-sm shadow-sm">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="flex justify-between items-center h-20">
              <Link href="/" className="flex items-center gap-2 group">
                <Image
                  src="/images/logo.png"
                  alt="Unifoods"
                  width={180}
                  height={60}
                  className="h-12 w-auto object-contain"
                  priority
                />
              </Link>
              <div className="flex items-center gap-5">
                <div className="w-5 h-5 bg-gray-200 rounded"></div>
                <div className="w-5 h-5 bg-gray-200 rounded"></div>
                <div className="w-5 h-5 bg-gray-200 rounded"></div>
                <div className="w-20 h-10 bg-gray-200 rounded-full"></div>
              </div>
            </div>
          </div>
        </div>
      </header>
    );
  }

  return (
    <>
      <>
        {/* Top Utility Bar */}
        <div className="bg-[#F0F4E8] border-b border-[#D4DFBD]">
          {/* ... existing utility bar content ... */}
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="flex justify-between items-center py-2 text-xs">
              <div className="flex items-center gap-3">
                <span className="text-gray-600">Follow us</span>
                <div className="flex gap-2">
                  <Link href="#" className="text-gray-600 hover:text-[#D97706] transition-colors">
                    <Linkedin size={14} />
                  </Link>
                  <Link href="#" className="text-gray-600 hover:text-[#D97706] transition-colors">
                    <Instagram size={14} />
                  </Link>
                  <Link href="#" className="text-gray-600 hover:text-[#D97706] transition-colors">
                    <Facebook size={14} />
                  </Link>
                </div>
              </div>

              <div className="hidden md:block text-center">
                <span className="text-[#D97706] font-medium">
                  Get 10% off your first wholesale order • Use code UNIFOODS10 at checkout!
                </span>
              </div>

              <div className="flex items-center gap-4 text-xs">
                <a href="tel:+919324856780" className="flex items-center gap-1 text-gray-600 hover:text-[#D97706] transition-colors">
                  <Phone size={12} />
                  <span className="hidden sm:inline">+91 93248 56780</span>
                </a>
                <a href="mailto:sales@unifoods.in" className="flex items-center gap-1 text-gray-600 hover:text-[#D97706] transition-colors">
                  <Mail size={12} />
                  <span className="hidden sm:inline">sales@unifoods.in</span>
                </a>
              </div>
            </div>
          </div>
        </div>

        {/* Main Navigation Bar */}
        <div className="sticky top-0 z-50 bg-white/95 backdrop-blur-sm shadow-sm w-full">
          {/* ... existing navbar content ... */}
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="flex justify-between items-center h-20">
              {/* Logo */}
              <Link href="/" className="flex items-center gap-2 group">
                <Image
                  src="/images/logo.png"
                  alt="Unifoods"
                  width={180}
                  height={60}
                  className="h-14 w-auto object-contain transition-transform group-hover:scale-105"
                  priority
                />
              </Link>

              {/* Navigation Menu */}
              <nav className={`hidden md:flex items-center gap-10 ${isSearchOpen ? 'opacity-0 pointer-events-none' : 'opacity-100'} transition-opacity duration-200`}>
                <Link href="/" className="text-sm font-medium text-[#111827] hover:text-[#D97706] transition-colors relative group">
                  Home
                  <span className="absolute -bottom-1 left-0 w-0 h-0.5 bg-[#D97706] group-hover:w-full transition-all"></span>
                </Link>
                <Link href="/products" className="text-sm font-medium text-[#111827] hover:text-[#D97706] transition-colors relative group">
                  Shop
                  <span className="absolute -bottom-1 left-0 w-0 h-0.5 bg-[#D97706] group-hover:w-full transition-all"></span>
                </Link>
                <Link href="/categories" className="text-sm font-medium text-[#111827] hover:text-[#D97706] transition-colors relative group">
                  Categories
                  <span className="absolute -bottom-1 left-0 w-0 h-0.5 bg-[#D97706] group-hover:w-full transition-all"></span>
                </Link>
                <Link href="/about" className="text-sm font-medium text-[#111827] hover:text-[#D97706] transition-colors relative group">
                  About Us
                  <span className="absolute -bottom-1 left-0 w-0 h-0.5 bg-[#D97706] group-hover:w-full transition-all"></span>
                </Link>
                <Link href="/contact" className="text-sm font-medium text-[#111827] hover:text-[#D97706] transition-colors relative group">
                  Contact
                  <span className="absolute -bottom-1 left-0 w-0 h-0.5 bg-[#D97706] group-hover:w-full transition-all"></span>
                </Link>
              </nav>

              {/* Right Icons */}
              <div className="flex items-center gap-5">

                {/* Search Container */}
                <div ref={searchContainerRef} className={`absolute right-4 left-4 md:left-auto md:relative flex items-center justify-end transition-all duration-300 ${isSearchOpen ? 'md:w-[400px] w-[calc(100%-32px)]' : 'w-auto'}`}>
                  {isSearchOpen ? (
                    <div className="relative w-full">
                      <input
                        ref={searchInputRef}
                        type="text"
                        value={searchQuery}
                        onChange={handleSearch}
                        placeholder="Search products..." // e.g., 'cherri' finds 'Cherry'
                        className="w-full pl-4 pr-10 py-2 rounded-full border border-gray-300 focus:outline-none focus:border-[#D97706] focus:ring-1 focus:ring-[#D97706] bg-white text-gray-900"
                      />
                      <button
                        onClick={toggleSearch}
                        className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 hover:text-red-500"
                      >
                        <X size={18} />
                      </button>

                      {/* Dropdown Results */}
                      {searchQuery && (
                        <div className="absolute top-full mt-2 w-full bg-white rounded-xl shadow-xl border border-gray-100 overflow-hidden z-50">
                          {searchResults.length > 0 ? (
                            <ul>
                              {searchResults.map((product) => (
                                <li key={product._id || product.id}>
                                  <Link
                                    href={`/products/${product._id || product.id}`}
                                    className="flex items-center gap-3 p-3 hover:bg-gray-50 transition-colors"
                                    onClick={() => setIsSearchOpen(false)}
                                  >
                                    {product.image && (
                                      <div className="w-10 h-10 relative rounded overflow-hidden bg-gray-100 flex-shrink-0">
                                        <img
                                          src={typeof product.image === 'string' ? product.image : (product.images?.[0]?.url || '/placeholder.png')}
                                          alt={product.name}
                                          className="object-cover w-full h-full"
                                        />
                                      </div>
                                    )}
                                    <div>
                                      <p className="text-sm font-medium text-gray-900 line-clamp-1">{product.name}</p>
                                      <p className="text-xs text-gray-500">{product.category?.name || 'Product'}</p>
                                    </div>
                                  </Link>
                                </li>
                              ))}
                            </ul>
                          ) : (
                            <div className="p-4 text-center text-gray-500 text-sm">
                              No matches found
                            </div>
                          )}
                        </div>
                      )}
                    </div>
                  ) : (
                    <button
                      onClick={toggleSearch}
                      className="text-gray-600 hover:text-[#D97706] transition-colors p-1"
                    >
                      <Search size={20} />
                    </button>
                  )}
                </div>

                {/* Hide other icons when search is open on mobile */}
                <div className={`flex items-center gap-5 transition-opacity duration-200 ${isSearchOpen ? 'hidden md:flex opacity-50' : 'flex'}`}>
                  {/* Wishlist Button */}
                  {isAuthenticated ? (
                    <Link href="/wishlist">
                      <button className="relative p-2 hover:bg-gray-100 rounded-full transition-colors">
                        <Heart size={20} />
                        {wishlistLoading ? (
                          <span className="absolute -top-1 -right-1 w-5 h-5 flex items-center justify-center">
                            <div className="w-4 h-4 border-2 border-gray-300 border-t-transparent rounded-full animate-spin"></div>
                          </span>
                        ) : wishlistCount > 0 ? (
                          <span className="absolute -top-1 -right-1 bg-[#D97706] text-white text-xs font-bold w-5 h-5 rounded-full flex items-center justify-center">
                            {wishlistCount > 9 ? '9+' : wishlistCount}
                          </span>
                        ) : null}
                      </button>
                    </Link>
                  ) : (
                    <button
                      onClick={handleLoginClick}
                      className="relative p-2 hover:bg-gray-100 rounded-full transition-colors"
                      title="Login to view wishlist"
                    >
                      <Heart size={20} />
                    </button>
                  )}

                  {/* Cart Button */}
                  <CartButton />

                  {/* Notification Button */}
                  {isAuthenticated && (
                    <Link href="/notifications">
                      <button className="relative p-2 hover:bg-gray-100 rounded-full transition-colors">
                        <Bell size={20} />
                        {notificationCount > 0 && (
                          <span className="absolute -top-1 -right-1 bg-amber-600 text-white text-xs font-bold w-5 h-5 rounded-full flex items-center justify-center">
                            {notificationCount > 9 ? '9+' : notificationCount}
                          </span>
                        )}
                      </button>
                    </Link>
                  )}

                  {/* User Authentication Section - Only in Desktop if search hidden */}
                  <div className="hidden lg:block">
                    {isAuthenticated ? (
                      <div className="flex items-center gap-3">
                        {/* User Info */}
                        <div className="flex items-center gap-2">
                          <Link href="/profile">
                            <div className="w-8 h-8 bg-[#D97706]/10 rounded-full flex items-center justify-center">
                              <User size={16} className="text-[#D97706]" />
                            </div>
                          </Link>
                        </div>

                        {/* Logout Button */}
                        <button
                          onClick={handleLogout}
                          className="text-gray-600 hover:text-[#D97706] transition-colors p-2 rounded-full hover:bg-gray-100"
                          title="Logout"
                        >
                          <svg
                            xmlns="http://www.w3.org/2000/svg"
                            width="20"
                            height="20"
                            viewBox="0 0 24 24"
                            fill="none"
                            stroke="currentColor"
                            strokeWidth="2"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                          >
                            <path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4" />
                            <polyline points="16 17 21 12 16 7" />
                            <line x1="21" y1="12" x2="9" y2="12" />
                          </svg>
                        </button>
                      </div>
                    ) : (
                      <button
                        onClick={handleLoginClick}
                        className="flex items-center gap-2 bg-[#D97706] text-white px-6 py-2.5 rounded-full hover:bg-[#B45309] transition-all shadow-md hover:shadow-lg text-sm font-medium"
                      >
                        <User size={18} />
                        Login / Register
                      </button>
                    )}
                  </div>
                  <button
                    onClick={handleLoginClick}
                    className="lg:hidden text-gray-600 hover:text-[#D97706] transition-colors"
                  >
                    <User size={20} />
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Login Modal */}
        <LoginModal
          isOpen={isLoginModalOpen}
          onClose={() => {
            setIsLoginModalOpen(false);
          }}
        />
      </>
    </>
  );
}

'use client';
import { Search, ArrowRight, MapPin, Loader2 } from 'lucide-react';
import Image from 'next/image';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { useState, useRef, useEffect } from 'react';

export default function Hero() {
  const router = useRouter();
  const [searchQuery, setSearchQuery] = useState('');
  const [locationName, setLocationName] = useState('Mumbai');
  const [isLocating, setIsLocating] = useState(false);
  const [searchResults, setSearchResults] = useState<any[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const searchContainerRef = useRef<HTMLDivElement>(null);
  const debounceRef = useRef<NodeJS.Timeout | null>(null);

  // Click outside to close search
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (searchContainerRef.current && !searchContainerRef.current.contains(event.target as Node)) {
        setIsSearchOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const performSearch = async (query: string) => {
    if (!query.trim()) {
      setSearchResults([]);
      setIsSearching(false);
      return;
    }

    setIsSearching(true);
    try {
      const API_BASE = process.env.NEXT_PUBLIC_API_BASE_URL || 'https://horeca-backend-six.vercel.app';
      const url = `${API_BASE}/api/products?q=${encodeURIComponent(query)}&limit=5`;
      const res = await fetch(url);
      const data = await res.json();

      if (data.success && Array.isArray(data.data?.items)) {
        setSearchResults(data.data.items);
        setIsSearchOpen(true);
      } else {
        setSearchResults([]);
      }
    } catch (error) {
      console.error("Search failed:", error);
      setSearchResults([]);
    } finally {
      setIsSearching(false);
    }
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const query = e.target.value;
    setSearchQuery(query);

    if (debounceRef.current) clearTimeout(debounceRef.current);

    if (!query.trim()) {
      setSearchResults([]);
      setIsSearchOpen(false);
      return;
    }

    debounceRef.current = setTimeout(() => {
      performSearch(query);
    }, 300); // 300ms debounce
  };

  const handleSearch = () => {
    if (!searchQuery.trim()) return;
    router.push(`/products?search=${encodeURIComponent(searchQuery.trim())}`);
    setIsSearchOpen(false);
  };

  // ... (location logic usually here) ...
  const handleLocationClick = () => {
    if (!navigator.geolocation) {
      alert("Geolocation is not supported by your browser");
      return;
    }

    setIsLocating(true);

    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;
        try {
          // Using OpenStreetMap Nominatim for free reverse geocoding
          const response = await fetch(
            `https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}`
          );
          const data = await response.json();

          if (data && data.address) {
            // Prefer city, then town, then village, then county
            const city = data.address.city || data.address.town || data.address.village || data.address.county || "Current Location";
            setLocationName(city);
          } else {
            setLocationName("Current Location");
          }
        } catch (error) {
          console.error("Error fetching location name:", error);
          setLocationName("Current Location");
        } finally {
          setIsLocating(false);
        }
      },
      (error) => {
        console.error("Error getting location:", error);
        alert("Unable to retrieve your location");
        setIsLocating(false);
      }
    );
  };

  return (
    <section className="relative bg-[#FAFAF7] overflow-hidden">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 pt-10 pb-10 lg:pt-16 lg:pb-12">
        <div className="grid lg:grid-cols-2 gap-16 items-center">
          {/* Left Content */}
          <div className="space-y-10 text-center lg:text-left order-2 lg:order-1 relative z-10">
            <div className="space-y-4">
              <h1 className="text-5xl lg:text-7xl font-extrabold text-[#111827] leading-tight tracking-tight">
                Quality Supplies <br />
                <span className="text-[#D97706]">Best Prices.</span>
              </h1>
              <p className="text-lg text-gray-500 max-w-lg mx-auto lg:mx-0 font-medium leading-relaxed">
                One-stop solution for all your Horeca needs.
                <span className="hidden lg:inline"> Fresh ingredients, packaging, and equipment delivered to your doorstep.</span>
              </p>
            </div>

            {/* Search Bar Container */}
            <div ref={searchContainerRef} className="relative bg-white p-2 rounded-full shadow-xl border border-gray-100 flex items-center max-w-xl mx-auto lg:mx-0 transform transition-all hover:scale-[1.01] z-50">

              {/* Location Mockup */}
              <button
                onClick={handleLocationClick}
                disabled={isLocating}
                className="hidden sm:flex items-center gap-2 pl-6 pr-4 border-r border-gray-100 text-sm font-medium text-gray-600 hover:text-[#D97706] transition-colors cursor-pointer"
                title="Detect my location"
              >
                {isLocating ? (
                  <Loader2 size={18} className="text-[#D97706] animate-spin" />
                ) : (
                  <MapPin size={18} className="text-[#D97706]" />
                )}
                <span className="truncate max-w-[100px]">{locationName}</span>
              </button>

              <div className="pl-4 text-gray-400">
                <Search size={20} />
              </div>
              <input
                type="text"
                value={searchQuery || ''}
                onChange={handleInputChange}
                onFocus={() => { if (searchResults.length > 0) setIsSearchOpen(true); }}
                onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
                placeholder="Search for sugar, flour, butter..."
                className="flex-1 w-full p-4 outline-none text-gray-700 placeholder-gray-400 bg-transparent text-lg"
              />
              <button
                onClick={handleSearch}
                className="bg-[#D97706] text-white px-8 py-3 rounded-full font-bold hover:bg-[#B45309] transition-colors"
              >
                Search
              </button>

              {/* Autocomplete Dropdown */}
              {isSearchOpen && searchResults.length > 0 && (
                <div className="absolute top-full left-0 mt-2 w-full bg-white rounded-2xl shadow-2xl border border-gray-100 overflow-hidden z-50">
                  <ul>
                    {searchResults.map((product) => (
                      <li key={product._id || product.id} className="border-b border-gray-50 last:border-0">
                        <Link
                          href={`/products/${product._id || product.id}`}
                          className="flex items-center gap-4 p-4 hover:bg-gray-50 transition-colors"
                          onClick={() => setIsSearchOpen(false)}
                        >
                          <div className="w-12 h-12 relative rounded-lg overflow-hidden bg-gray-100 flex-shrink-0 border border-gray-100">
                            <img
                              src={typeof product.image === 'string' ? product.image : (product.images?.[0]?.url || '/placeholder.png')}
                              alt={product.name}
                              className="object-cover w-full h-full"
                            />
                          </div>
                          <div className="flex-1 text-left">
                            <p className="text-base font-semibold text-gray-900 line-clamp-1">{product.name}</p>
                            <p className="text-sm text-gray-500">{product.category?.name || 'Product'}</p>
                          </div>
                          <div className="text-right">
                            <ArrowRight size={16} className="text-gray-300" />
                          </div>
                        </Link>
                      </li>
                    ))}
                  </ul>
                  <div className="p-3 bg-gray-50 text-center border-t border-gray-100">
                    <button onClick={handleSearch} className="text-xs font-bold text-[#D97706] hover:underline">
                      View all results
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Right Images */}
          <div className="relative order-1 lg:order-2">
            {/* Main Hero Composite */}
            <div className="relative z-10">
              <div className="relative h-[28rem] w-full">
                {/* We can use a single composed image or a nice grid. 
                      For Hyperpure style, let's keep it clean. 
                      Maybe a single high-quality collage or the existing grid if it looks neat. 
                      Let's stick to the existing grid but simplified props. */}
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-4 pt-8">
                    <div className="relative h-48 bg-white rounded-2xl overflow-hidden shadow-sm border border-gray-100">
                      <Image src="/images/hero/hero-left.jpg" alt="Fresh" fill className="object-cover" />
                    </div>
                    <div className="relative h-32 bg-[#FFF3E0] rounded-2xl overflow-hidden shadow-sm flex items-center justify-center">
                      <Image src="/images/products/flour.jpg" alt="Flour" fill className="object-contain p-4" />
                    </div>
                  </div>
                  <div className="space-y-4">
                    <div className="relative h-32 bg-[#E8F5E9] rounded-2xl overflow-hidden shadow-sm flex items-center justify-center">
                      <Image src="/images/products/chocolate.jpg" alt="Chocolate" fill className="object-contain p-4" />
                    </div>
                    <div className="relative h-48 bg-white rounded-2xl overflow-hidden shadow-sm border border-gray-100">
                      <Image src="/images/hero/hero-right.jpg" alt="Quality" fill className="object-cover" />
                    </div>
                  </div>
                </div>
              </div>
            </div>

            {/* Subtle Decor */}
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[120%] h-[120%] bg-orange-100/50 rounded-full blur-3xl -z-10"></div>
          </div>
        </div>
      </div>
    </section>
  );
}

'use client';

import { useState } from 'react';
import { BusinessType, BusinessSize } from '@/lib/types/user';
import { Building2, Users, Calendar, Store, Coffee, UtensilsCrossed, Hotel, ChefHat, ShoppingBag, Factory, Truck } from 'lucide-react';

interface BasicInfoFormProps {
  onSubmit: (data: {
    businessName: string;
    businessType: BusinessType;
    businessSize: BusinessSize;
    yearEstablished: number;
  }) => void;
  initialData?: {
    businessName: string;
    businessType: BusinessType;
    businessSize: BusinessSize;
    yearEstablished: number;
  };
}

export default function BasicInfoForm({ onSubmit, initialData }: BasicInfoFormProps) {
  const [formData, setFormData] = useState({
    businessName: initialData?.businessName || '',
    businessType: initialData?.businessType || '' as BusinessType,
    businessSize: initialData?.businessSize || '' as BusinessSize,
    yearEstablished: initialData?.yearEstablished || new Date().getFullYear(),
  });

  const [errors, setErrors] = useState<Record<string, string>>({});

  const businessTypes = [
    { id: 'bakery' as BusinessType, name: 'Bakery', icon: Store, desc: 'Bread, cakes, pastries' },
    { id: 'cafe' as BusinessType, name: 'Café', icon: Coffee, desc: 'Coffee shop, snacks' },
    { id: 'restaurant' as BusinessType, name: 'Restaurant', icon: UtensilsCrossed, desc: 'Fine dining, QSR' },
    { id: 'hotel' as BusinessType, name: 'Hotel', icon: Hotel, desc: 'Hospitality, catering' },
    { id: 'catering' as BusinessType, name: 'Catering Service', icon: ChefHat, desc: 'Event catering' },
    { id: 'retail' as BusinessType, name: 'Retail Store', icon: ShoppingBag, desc: 'Grocery, supermarket' },
    { id: 'manufacturer' as BusinessType, name: 'Manufacturer', icon: Factory, desc: 'Food production' },
    { id: 'distributor' as BusinessType, name: 'Distributor', icon: Truck, desc: 'Wholesale supplier' },
  ];

  const businessSizes = [
    { id: 'individual' as BusinessSize, name: 'Individual/Freelancer', range: '< ₹10L/year' },
    { id: 'small' as BusinessSize, name: 'Small Business', range: '₹10L - ₹50L/year' },
    { id: 'medium' as BusinessSize, name: 'Medium Business', range: '₹50L - ₹5Cr/year' },
    { id: 'large' as BusinessSize, name: 'Large Business', range: '₹5Cr - ₹25Cr/year' },
    { id: 'enterprise' as BusinessSize, name: 'Enterprise', range: '> ₹25Cr/year' },
  ];

  const currentYear = new Date().getFullYear();
  const years = Array.from({ length: 100 }, (_, i) => currentYear - i);

  const handleChange = (field: string, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    if (errors[field]) {
      setErrors(prev => ({ ...prev, [field]: '' }));
    }
  };

  const validateForm = () => {
    const newErrors: Record<string, string> = {};

    if (!formData.businessName.trim()) {
      newErrors.businessName = 'Business name is required';
    } else if (formData.businessName.length < 3) {
      newErrors.businessName = 'Business name must be at least 3 characters';
    }

    if (!formData.businessType) {
      newErrors.businessType = 'Please select a business type';
    }

    if (!formData.businessSize) {
      newErrors.businessSize = 'Please select a business size';
    }

    if (formData.yearEstablished > currentYear) {
      newErrors.yearEstablished = 'Year cannot be in the future';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validateForm()) {
      onSubmit(formData);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-8">
      {/* Business Name */}
      <div>
        <label className="block text-sm font-medium text-[#111827] mb-2">
          Business Name *
        </label>
        <div className="relative">
          <input
            type="text"
            value={formData.businessName}
            onChange={(e) => handleChange('businessName', e.target.value)}
            className={`w-full px-4 py-3 pl-11 border ${errors.businessName ? 'border-red-500' : 'border-gray-300'
              } rounded-xl focus:outline-none focus:border-[#D97706] transition-colors`}
            placeholder="Your Business Name Pvt. Ltd."
          />
          <Building2 size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
        </div>
        {errors.businessName && (
          <p className="text-xs text-red-500 mt-1">{errors.businessName}</p>
        )}
      </div>

      {/* Business Type */}
      <div>
        <label className="block text-sm font-medium text-[#111827] mb-3">
          Business Type *
        </label>
        <div className="grid sm:grid-cols-2 lg:grid-cols-4 gap-3">
          {businessTypes.map((type) => {
            const Icon = type.icon;
            const isSelected = formData.businessType === type.id;

            return (
              <label
                key={type.id}
                className={`relative cursor-pointer transition-all ${isSelected ? 'scale-[1.02]' : 'hover:scale-[1.01]'
                  }`}
              >
                <div
                  className={`p-4 border-2 rounded-xl transition-all ${isSelected
                      ? 'border-[#D97706] bg-[#E8F5E9] shadow-md'
                      : 'border-gray-200 hover:border-gray-300'
                    }`}
                >
                  <input
                    type="radio"
                    name="businessType"
                    value={type.id}
                    checked={isSelected}
                    onChange={(e) => handleChange('businessType', e.target.value)}
                    className="sr-only"
                  />
                  <div className="flex flex-col items-center text-center">
                    <div
                      className={`w-12 h-12 rounded-xl flex items-center justify-center mb-2 ${isSelected ? 'bg-[#D97706] text-white' : 'bg-gray-100 text-gray-600'
                        }`}
                    >
                      <Icon size={24} />
                    </div>
                    <h3 className="font-semibold text-[#111827] text-sm mb-1">
                      {type.name}
                    </h3>
                    <p className="text-xs text-gray-600">{type.desc}</p>
                  </div>
                </div>
              </label>
            );
          })}
        </div>
        {errors.businessType && (
          <p className="text-xs text-red-500 mt-2">{errors.businessType}</p>
        )}
      </div>

      {/* Business Size */}
      <div>
        <label className="block text-sm font-medium text-[#111827] mb-3">
          Business Size *
        </label>
        <div className="space-y-3">
          {businessSizes.map((size) => {
            const isSelected = formData.businessSize === size.id;

            return (
              <label
                key={size.id}
                className="block cursor-pointer"
              >
                <div
                  className={`p-4 border-2 rounded-xl transition-all flex items-center justify-between ${isSelected
                      ? 'border-[#D97706] bg-[#E8F5E9]'
                      : 'border-gray-200 hover:border-gray-300'
                    }`}
                >
                  <div className="flex items-center gap-3">
                    <input
                      type="radio"
                      name="businessSize"
                      value={size.id}
                      checked={isSelected}
                      onChange={(e) => handleChange('businessSize', e.target.value)}
                      className="w-5 h-5 text-[#D97706] focus:ring-[#D97706]"
                    />
                    <div>
                      <h3 className="font-semibold text-[#111827] text-sm">
                        {size.name}
                      </h3>
                      <p className="text-xs text-gray-600">{size.range}</p>
                    </div>
                  </div>
                  <Users size={20} className={isSelected ? 'text-[#D97706]' : 'text-gray-400'} />
                </div>
              </label>
            );
          })}
        </div>
        {errors.businessSize && (
          <p className="text-xs text-red-500 mt-2">{errors.businessSize}</p>
        )}
      </div>

      {/* Year Established */}
      <div>
        <label className="block text-sm font-medium text-[#111827] mb-2">
          Year Established *
        </label>
        <div className="relative">
          <select
            value={formData.yearEstablished}
            onChange={(e) => handleChange('yearEstablished', parseInt(e.target.value))}
            className={`w-full px-4 py-3 pl-11 border ${errors.yearEstablished ? 'border-red-500' : 'border-gray-300'
              } rounded-xl focus:outline-none focus:border-[#D97706] transition-colors bg-white`}
          >
            {years.map((year) => (
              <option key={year} value={year}>
                {year}
              </option>
            ))}
          </select>
          <Calendar size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
        </div>
        {errors.yearEstablished && (
          <p className="text-xs text-red-500 mt-1">{errors.yearEstablished}</p>
        )}
      </div>

      {/* Submit Button */}
      <button
        type="submit"
        className="w-full bg-[#D97706] text-white py-4 rounded-full hover:bg-[#B45309] transition-all font-semibold shadow-md hover:shadow-lg"
      >
        Continue to Contact Information
      </button>
    </form>
  );
}

'use client';

import { useState } from 'react';
import { User, Mail, Lock, Phone, Globe } from 'lucide-react';

interface ContactInfoFormProps {
  onSubmit: (data: {
    contactPerson: string;
    email: string;
    password: string;
    phone: string;
    alternatePhone?: string;
    website?: string;
  }) => void;
  initialData?: {
    contactPerson: string;
    email: string;
    password: string;
    phone: string;
    alternatePhone?: string;
    website?: string;
  };
}

export default function ContactInfoForm({ onSubmit, initialData }: ContactInfoFormProps) {
  const [formData, setFormData] = useState({
    contactPerson: initialData?.contactPerson || '',
    email: initialData?.email || '',
    password: initialData?.password || '',
    confirmPassword: '',
    phone: initialData?.phone || '',
    alternatePhone: initialData?.alternatePhone || '',
    website: initialData?.website || '',
  });

  const [errors, setErrors] = useState<Record<string, string>>({});
  const [showPassword, setShowPassword] = useState(false);

  const handleChange = (field: string, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    if (errors[field]) {
      setErrors(prev => ({ ...prev, [field]: '' }));
    }
  };

  const validateForm = () => {
    const newErrors: Record<string, string> = {};

    // Contact Person
    if (!formData.contactPerson.trim()) {
      newErrors.contactPerson = 'Contact person name is required';
    }

    // Email
    if (!formData.email.trim()) {
      newErrors.email = 'Email is required';
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) {
      newErrors.email = 'Invalid email address';
    }

    // Password
    if (!formData.password) {
      newErrors.password = 'Password is required';
    } else if (formData.password.length < 8) {
      newErrors.password = 'Password must be at least 8 characters';
    } else if (!/(?=.*[a-z])(?=.*[A-Z])(?=.*\d)/.test(formData.password)) {
      newErrors.password = 'Password must contain uppercase, lowercase, and number';
    }

    // Confirm Password
    if (formData.password !== formData.confirmPassword) {
      newErrors.confirmPassword = 'Passwords do not match';
    }

    // Phone
    if (!formData.phone.trim()) {
      newErrors.phone = 'Phone number is required';
    } else if (!/^[6-9]\d{9}$/.test(formData.phone)) {
      newErrors.phone = 'Invalid phone number (10 digits, starts with 6-9)';
    }

    // Alternate Phone (optional)
    if (formData.alternatePhone && !/^[6-9]\d{9}$/.test(formData.alternatePhone)) {
      newErrors.alternatePhone = 'Invalid phone number';
    }

    // Website (optional)
    if (formData.website && !/^https?:\/\/.+\..+/.test(formData.website)) {
      newErrors.website = 'Invalid website URL (must start with http:// or https://)';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validateForm()) {
      const { confirmPassword, ...submitData } = formData;
      onSubmit(submitData);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      {/* Contact Person */}
      <div>
        <label className="block text-sm font-medium text-[#111827] mb-2">
          Contact Person Name *
        </label>
        <div className="relative">
          <input
            type="text"
            value={formData.contactPerson}
            onChange={(e) => handleChange('contactPerson', e.target.value)}
            className={`w-full px-4 py-3 pl-11 border ${errors.contactPerson ? 'border-red-500' : 'border-gray-300'
              } rounded-xl focus:outline-none focus:border-[#D97706] transition-colors`}
            placeholder="John Doe"
          />
          <User size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
        </div>
        {errors.contactPerson && (
          <p className="text-xs text-red-500 mt-1">{errors.contactPerson}</p>
        )}
      </div>

      {/* Email */}
      <div>
        <label className="block text-sm font-medium text-[#111827] mb-2">
          Business Email *
        </label>
        <div className="relative">
          <input
            type="email"
            value={formData.email}
            onChange={(e) => handleChange('email', e.target.value)}
            className={`w-full px-4 py-3 pl-11 border ${errors.email ? 'border-red-500' : 'border-gray-300'
              } rounded-xl focus:outline-none focus:border-[#D97706] transition-colors`}
            placeholder="business@example.com"
          />
          <Mail size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
        </div>
        {errors.email && (
          <p className="text-xs text-red-500 mt-1">{errors.email}</p>
        )}
      </div>

      <div className="grid md:grid-cols-2 gap-6">
        {/* Password */}
        <div>
          <label className="block text-sm font-medium text-[#111827] mb-2">
            Password *
          </label>
          <div className="relative">
            <input
              type={showPassword ? 'text' : 'password'}
              value={formData.password}
              onChange={(e) => handleChange('password', e.target.value)}
              className={`w-full px-4 py-3 pl-11 border ${errors.password ? 'border-red-500' : 'border-gray-300'
                } rounded-xl focus:outline-none focus:border-[#D97706] transition-colors`}
              placeholder="••••••••"
            />
            <Lock size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
          </div>
          {errors.password && (
            <p className="text-xs text-red-500 mt-1">{errors.password}</p>
          )}
          <p className="text-xs text-gray-500 mt-1">
            Min 8 characters, 1 uppercase, 1 lowercase, 1 number
          </p>
        </div>

        {/* Confirm Password */}
        <div>
          <label className="block text-sm font-medium text-[#111827] mb-2">
            Confirm Password *
          </label>
          <div className="relative">
            <input
              type={showPassword ? 'text' : 'password'}
              value={formData.confirmPassword}
              onChange={(e) => handleChange('confirmPassword', e.target.value)}
              className={`w-full px-4 py-3 pl-11 border ${errors.confirmPassword ? 'border-red-500' : 'border-gray-300'
                } rounded-xl focus:outline-none focus:border-[#D97706] transition-colors`}
              placeholder="••••••••"
            />
            <Lock size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
          </div>
          {errors.confirmPassword && (
            <p className="text-xs text-red-500 mt-1">{errors.confirmPassword}</p>
          )}
        </div>
      </div>

      {/* Show Password Toggle */}
      <label className="flex items-center gap-2 cursor-pointer">
        <input
          type="checkbox"
          checked={showPassword}
          onChange={(e) => setShowPassword(e.target.checked)}
          className="w-4 h-4 text-[#D97706] focus:ring-[#D97706] rounded"
        />
        <span className="text-sm text-gray-700">Show passwords</span>
      </label>

      <div className="grid md:grid-cols-2 gap-6">
        {/* Phone */}
        <div>
          <label className="block text-sm font-medium text-[#111827] mb-2">
            Primary Phone Number *
          </label>
          <div className="relative">
            <input
              type="tel"
              value={formData.phone}
              onChange={(e) => handleChange('phone', e.target.value)}
              className={`w-full px-4 py-3 pl-11 border ${errors.phone ? 'border-red-500' : 'border-gray-300'
                } rounded-xl focus:outline-none focus:border-[#D97706] transition-colors`}
              placeholder="9322506730"
              maxLength={10}
            />
            <Phone size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
          </div>
          {errors.phone && (
            <p className="text-xs text-red-500 mt-1">{errors.phone}</p>
          )}
        </div>

        {/* Alternate Phone */}
        <div>
          <label className="block text-sm font-medium text-[#111827] mb-2">
            Alternate Phone (Optional)
          </label>
          <div className="relative">
            <input
              type="tel"
              value={formData.alternatePhone}
              onChange={(e) => handleChange('alternatePhone', e.target.value)}
              className={`w-full px-4 py-3 pl-11 border ${errors.alternatePhone ? 'border-red-500' : 'border-gray-300'
                } rounded-xl focus:outline-none focus:border-[#D97706] transition-colors`}
              placeholder="9322506730"
              maxLength={10}
            />
            <Phone size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
          </div>
          {errors.alternatePhone && (
            <p className="text-xs text-red-500 mt-1">{errors.alternatePhone}</p>
          )}
        </div>
      </div>

      {/* Website */}
      <div>
        <label className="block text-sm font-medium text-[#111827] mb-2">
          Website (Optional)
        </label>
        <div className="relative">
          <input
            type="url"
            value={formData.website}
            onChange={(e) => handleChange('website', e.target.value)}
            className={`w-full px-4 py-3 pl-11 border ${errors.website ? 'border-red-500' : 'border-gray-300'
              } rounded-xl focus:outline-none focus:border-[#D97706] transition-colors`}
            placeholder="https://www.yourbusiness.com"
          />
          <Globe size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
        </div>
        {errors.website && (
          <p className="text-xs text-red-500 mt-1">{errors.website}</p>
        )}
      </div>

      {/* Submit Button */}
      <button
        type="submit"
        className="w-full bg-[#D97706] text-white py-4 rounded-full hover:bg-[#B45309] transition-all font-semibold shadow-md hover:shadow-lg"
      >
        Continue to Business Address
      </button>
    </form>
  );
}

'use client';

import { useState } from 'react';
import { FileText, Upload, CheckCircle, X } from 'lucide-react';

interface DocumentsFormProps {
  onSubmit: (data: {
    gstNumber?: string;
    panNumber?: string;
    fssaiNumber?: string;
    tradeLicenseNumber?: string;
    monthlyPurchaseVolume?: string;
    agreeToTerms: boolean;
  }) => void;
  initialData?: any;
}

export default function DocumentsForm({ onSubmit, initialData }: DocumentsFormProps) {
  const [formData, setFormData] = useState({
    gstNumber: initialData?.gstNumber || '',
    panNumber: initialData?.panNumber || '',
    fssaiNumber: initialData?.fssaiNumber || '',
    tradeLicenseNumber: initialData?.tradeLicenseNumber || '',
    monthlyPurchaseVolume: initialData?.monthlyPurchaseVolume || '',
    agreeToTerms: false,
  });

  const [errors, setErrors] = useState<Record<string, string>>({});
  const [uploadedDocs, setUploadedDocs] = useState<Record<string, File>>({});

  const purchaseVolumes = [
    '< ₹50,000',
    '₹50,000 - ₹1 Lakh',
    '₹1 Lakh - ₹5 Lakhs',
    '₹5 Lakhs - ₹25 Lakhs',
    '> ₹25 Lakhs',
  ];

  const handleChange = (field: string, value: string | boolean) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    if (errors[field]) {
      setErrors(prev => ({ ...prev, [field]: '' }));
    }
  };

  const handleFileUpload = (docType: string, file: File) => {
    setUploadedDocs(prev => ({ ...prev, [docType]: file }));
  };

  const removeFile = (docType: string) => {
    setUploadedDocs(prev => {
      const newDocs = { ...prev };
      delete newDocs[docType];
      return newDocs;
    });
  };

  const validateForm = () => {
    const newErrors: Record<string, string> = {};

    // GST validation (optional but if provided, validate)
    if (formData.gstNumber && !/^\d{2}[A-Z]{5}\d{4}[A-Z]{1}[A-Z\d]{1}[Z]{1}[A-Z\d]{1}$/.test(formData.gstNumber)) {
      newErrors.gstNumber = 'Invalid GST format (e.g., 22AAAAA0000A1Z5)';
    }

    // PAN validation (optional but if provided, validate)
    if (formData.panNumber && !/^[A-Z]{5}\d{4}[A-Z]{1}$/.test(formData.panNumber)) {
      newErrors.panNumber = 'Invalid PAN format (e.g., ABCDE1234F)';
    }

    // FSSAI validation (optional)
    if (formData.fssaiNumber && !/^\d{14}$/.test(formData.fssaiNumber)) {
      newErrors.fssaiNumber = 'Invalid FSSAI number (14 digits)';
    }

    // Terms agreement
    if (!formData.agreeToTerms) {
      newErrors.agreeToTerms = 'You must agree to the terms and conditions';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validateForm()) {
      onSubmit(formData);
    }
  };

  const FileUploadCard = ({ label, docType, required = false }: { label: string; docType: string; required?: boolean }) => {
    const file = uploadedDocs[docType];

    return (
      <div className="border-2 border-dashed border-gray-300 rounded-xl p-6 hover:border-[#D97706] transition-colors">
        <div className="flex items-start justify-between mb-3">
          <div>
            <h4 className="font-medium text-[#111827] text-sm mb-1">
              {label} {required && <span className="text-red-500">*</span>}
            </h4>
            <p className="text-xs text-gray-600">PDF, JPG, PNG (Max 5MB)</p>
          </div>
          <FileText size={20} className="text-gray-400" />
        </div>

        {file ? (
          <div className="bg-[#E8F5E9] rounded-lg p-3 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <CheckCircle size={16} className="text-[#D97706]" />
              <span className="text-sm text-[#111827] truncate max-w-[200px]">
                {file.name}
              </span>
            </div>
            <button
              type="button"
              onClick={() => removeFile(docType)}
              className="text-red-500 hover:text-red-600"
            >
              <X size={16} />
            </button>
          </div>
        ) : (
          <label className="flex flex-col items-center gap-2 cursor-pointer">
            <input
              type="file"
              accept=".pdf,.jpg,.jpeg,.png"
              onChange={(e) => {
                const file = e.target.files?.[0];
                if (file) handleFileUpload(docType, file);
              }}
              className="hidden"
            />
            <Upload size={24} className="text-gray-400" />
            <span className="text-sm text-[#D97706] font-medium">Click to upload</span>
          </label>
        )}
      </div>
    );
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-8">
      {/* Document Numbers */}
      <div className="bg-[#E8F5E9] rounded-2xl p-6">
        <h3 className="font-semibold text-[#111827] mb-4">Business Registration Numbers</h3>
        <p className="text-sm text-gray-700 mb-4">
          Provide your business registration numbers. These help verify your business and may be required for tax compliance.
        </p>

        <div className="space-y-4">
          {/* GST Number */}
          <div>
            <label className="block text-sm font-medium text-[#111827] mb-2">
              GST Number (Optional)
            </label>
            <input
              type="text"
              value={formData.gstNumber}
              onChange={(e) => handleChange('gstNumber', e.target.value.toUpperCase())}
              className={`w-full px-4 py-3 border ${errors.gstNumber ? 'border-red-500' : 'border-gray-300'
                } rounded-xl focus:outline-none focus:border-[#D97706] transition-colors bg-white`}
              placeholder="22AAAAA0000A1Z5"
              maxLength={15}
            />
            {errors.gstNumber && (
              <p className="text-xs text-red-500 mt-1">{errors.gstNumber}</p>
            )}
          </div>

          {/* PAN Number */}
          <div>
            <label className="block text-sm font-medium text-[#111827] mb-2">
              PAN Number (Optional)
            </label>
            <input
              type="text"
              value={formData.panNumber}
              onChange={(e) => handleChange('panNumber', e.target.value.toUpperCase())}
              className={`w-full px-4 py-3 border ${errors.panNumber ? 'border-red-500' : 'border-gray-300'
                } rounded-xl focus:outline-none focus:border-[#D97706] transition-colors bg-white`}
              placeholder="ABCDE1234F"
              maxLength={10}
            />
            {errors.panNumber && (
              <p className="text-xs text-red-500 mt-1">{errors.panNumber}</p>
            )}
          </div>

          {/* FSSAI Number */}
          <div>
            <label className="block text-sm font-medium text-[#111827] mb-2">
              FSSAI License Number (Optional)
            </label>
            <input
              type="text"
              value={formData.fssaiNumber}
              onChange={(e) => handleChange('fssaiNumber', e.target.value)}
              className={`w-full px-4 py-3 border ${errors.fssaiNumber ? 'border-red-500' : 'border-gray-300'
                } rounded-xl focus:outline-none focus:border-[#D97706] transition-colors bg-white`}
              placeholder="12345678901234"
              maxLength={14}
            />
            {errors.fssaiNumber && (
              <p className="text-xs text-red-500 mt-1">{errors.fssaiNumber}</p>
            )}
          </div>

          {/* Trade License Number */}
          <div>
            <label className="block text-sm font-medium text-[#111827] mb-2">
              Trade License Number (Optional)
            </label>
            <input
              type="text"
              value={formData.tradeLicenseNumber}
              onChange={(e) => handleChange('tradeLicenseNumber', e.target.value)}
              className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:outline-none focus:border-[#D97706] transition-colors bg-white"
              placeholder="Enter trade license number"
            />
          </div>
        </div>
      </div>

      {/* Document Uploads */}
      <div>
        <h3 className="font-semibold text-[#111827] mb-2">Upload Documents (Optional)</h3>
        <p className="text-sm text-gray-600 mb-4">
          Upload business documents for faster verification. You can also upload these later from your profile.
        </p>

        <div className="grid md:grid-cols-2 gap-4">
          <FileUploadCard label="GST Certificate" docType="gst" />
          <FileUploadCard label="PAN Card" docType="pan" />
          <FileUploadCard label="FSSAI License" docType="fssai" />
          <FileUploadCard label="Trade License" docType="trade" />
        </div>
      </div>

      {/* Purchase Volume */}
      <div>
        <label className="block text-sm font-medium text-[#111827] mb-3">
          Expected Monthly Purchase Volume (Optional)
        </label>
        <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 gap-3">
          {purchaseVolumes.map((volume) => (
            <label
              key={volume}
              className={`p-3 border-2 rounded-xl cursor-pointer transition-all text-center ${formData.monthlyPurchaseVolume === volume
                  ? 'border-[#D97706] bg-[#E8F5E9]'
                  : 'border-gray-200 hover:border-gray-300'
                }`}
            >
              <input
                type="radio"
                name="purchaseVolume"
                value={volume}
                checked={formData.monthlyPurchaseVolume === volume}
                onChange={(e) => handleChange('monthlyPurchaseVolume', e.target.value)}
                className="sr-only"
              />
              <span className="text-sm font-medium text-[#111827]">{volume}</span>
            </label>
          ))}
        </div>
      </div>

      {/* Terms Agreement */}
      <div className="bg-gray-50 rounded-xl p-6">
        <label className="flex items-start gap-3 cursor-pointer">
          <input
            type="checkbox"
            checked={formData.agreeToTerms}
            onChange={(e) => handleChange('agreeToTerms', e.target.checked)}
            className="w-5 h-5 text-[#D97706] focus:ring-[#D97706] rounded mt-0.5"
          />
          <div className="flex-1">
            <p className="text-sm text-gray-700">
              I agree to the{' '}
              <a href="/terms" className="text-[#D97706] hover:underline font-medium">
                Terms & Conditions
              </a>
              {' '}and{' '}
              <a href="/privacy" className="text-[#D97706] hover:underline font-medium">
                Privacy Policy
              </a>
              . I confirm that all information provided is accurate and I'm authorized to register this business.
            </p>
          </div>
        </label>
        {errors.agreeToTerms && (
          <p className="text-xs text-red-500 mt-2 ml-8">{errors.agreeToTerms}</p>
        )}
      </div>

      {/* Submit Button */}
      <button
        type="submit"
        className="w-full bg-[#D97706] text-white py-4 rounded-full hover:bg-[#B45309] transition-all font-semibold shadow-md hover:shadow-lg"
      >
        Complete Registration
      </button>
    </form>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { CheckCircle } from 'lucide-react';

interface AddToCartToastProps {
  show: boolean;
  productName: string;
  onClose: () => void;
}

export default function AddToCartToast({ show, productName, onClose }: AddToCartToastProps) {
  useEffect(() => {
    if (show) {
      const timer = setTimeout(() => {
        onClose();
      }, 3000);
      return () => clearTimeout(timer);
    }
  }, [show, onClose]);

  if (!show) return null;

  return (
    <div className="fixed top-24 right-4 bg-white rounded-2xl soft-shadow p-4 flex items-center gap-3 z-50 animate-slide-in">
      <div className="w-10 h-10 bg-[#E8F5E9] rounded-full flex items-center justify-center">
        <CheckCircle size={20} className="text-[#D97706]" />
      </div>
      <div>
        <p className="font-semibold text-[#111827] text-sm">Added to cart!</p>
        <p className="text-xs text-gray-600">{productName}</p>
      </div>
    </div>
  );
}

