'use client';

import React, { useEffect, useState, useRef } from 'react';
import Map, { Marker, Source, Layer, MapRef } from 'react-map-gl/mapbox';
import 'mapbox-gl/dist/mapbox-gl.css';
import { MapPin } from 'lucide-react';
import { animate } from 'framer-motion';

const MAPBOX_TOKEN = "pk.eyJ1Ijoic2FtZWVyMjcyOSIsImEiOiJjbWswdWtmMGMwMDdmM2Zxc3ludjF2eTZkIn0._DvjqPsOzDNAlUIPs4xJlQ";

interface OrderTrackingMapProps {
    destination: {
        lat: number;
        lng: number;
        address?: string;
    };
    status: string;
}

const OrderTrackingMap: React.FC<OrderTrackingMapProps> = ({ destination, status }) => {
    const mapRef = useRef<MapRef>(null);
    const [driverLoc, setDriverLoc] = useState<{ lat: number; lng: number } | null>(null);
    const [mapLoaded, setMapLoaded] = useState(false);

    // Initial driver start point (simulate 2-3km away)
    const startPoint = {
        lat: destination.lat - 0.015,
        lng: destination.lng - 0.015
    };

    // State for bearing (rotation)
    const [driverBearing, setDriverBearing] = useState<number>(0);

    // Poll for driver location every 4 seconds
    useEffect(() => {
        if (!['out_for_delivery', 'shipped'].includes(status)) {
            setDriverLoc(null);
            return;
        }

        const pollLocation = async () => {
            try {
                // Get Order ID from URL
                const pathParts = window.location.pathname.split('/');
                const orderId = pathParts[pathParts.length - 1]; // /orders/[id]

                if (!orderId) return;

                // Use environment variable for production
                const backendUrl = process.env.NEXT_PUBLIC_API_BASE_URL || "http://horeca-backend-six.vercel.app";
                const res = await fetch(`${backendUrl}/api/order?id=${orderId}`);
                const data = await res.json();

                if (data.success && data.order?.driverLocation) {
                    const loc = data.order.driverLocation;
                    if (loc.lat && loc.lng) {
                        setDriverLoc({ lat: loc.lat, lng: loc.lng });
                        if (loc.bearing !== undefined) setDriverBearing(loc.bearing);
                    }
                }
            } catch (err) {
                console.error("Polling Error:", err);
            }
        };

        // Initial fetch
        pollLocation();

        const interval = setInterval(pollLocation, 4000); // 4 seconds

        return () => clearInterval(interval);
    }, [status]);

    // Determine simplified bounds when map loads or status changes
    useEffect(() => {
        if (mapLoaded && mapRef.current) {
            if (driverLoc) {
                // Safely access map instance
                const mapInstance = mapRef.current.getMap();
                if (mapInstance) {
                    try {
                        mapInstance.fitBounds(
                            [
                                [Math.min(driverLoc.lng, destination.lng), Math.min(driverLoc.lat, destination.lat)],
                                [Math.max(driverLoc.lng, destination.lng), Math.max(driverLoc.lat, destination.lat)]
                            ],
                            {
                                padding: { top: 160, bottom: 120, left: 50, right: 50 },
                                duration: 2000
                            }
                        );
                    } catch (e) {
                        console.error("Error fitting bounds:", e);
                    }
                }
            } else {
                mapRef.current.flyTo({
                    center: [destination.lng, destination.lat],
                    zoom: 15,
                    duration: 2000
                });
            }
        }
    }, [mapLoaded, driverLoc === null]); // Trigger when driverLoc availability changes

    // Route Line GeoJSON
    const routeGeoJSON = {
        type: 'Feature',
        properties: {},
        geometry: {
            type: 'LineString',
            coordinates: driverLoc ? [
                [driverLoc.lng, driverLoc.lat],
                [destination.lng, destination.lat]
            ] : []
        }
    };

    return (
        <div className="w-full h-full relative">
            <Map
                ref={mapRef}
                initialViewState={{
                    latitude: destination.lat,
                    longitude: destination.lng,
                    zoom: 15,
                    pitch: 60, // 3D view
                    bearing: -17.6,
                }}
                mapboxAccessToken={MAPBOX_TOKEN}
                mapStyle="mapbox://styles/mapbox/standard"
                style={{ width: '100%', height: '100%' }}
                maxPitch={85}
                onLoad={() => setMapLoaded(true)}
                attributionControl={false}
            >
                {/* Destination Marker */}
                <Marker latitude={destination.lat} longitude={destination.lng} anchor="bottom">
                    <div className="relative flex flex-col items-center group">
                        <div className="w-4 h-4 bg-orange-500 rounded-full animate-ping absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 opacity-20"></div>
                        <div className="bg-white p-2.5 rounded-full shadow-xl border-2 border-orange-500 z-10">
                            <MapPin className="text-orange-600 fill-orange-100" size={24} />
                        </div>
                        <div className="bg-white/90 backdrop-blur-md px-3 py-1 mt-2 rounded-full text-xs font-bold shadow-lg border border-gray-100 transform transition-all group-hover:scale-110">
                            Delivery Location
                        </div>
                    </div>
                </Marker>

                {/* Driver Marker - Real-time */}
                {driverLoc && (
                    <Marker
                        latitude={driverLoc.lat}
                        longitude={driverLoc.lng}
                        anchor="bottom"
                        rotation={driverBearing - 90} // Adjusting for Right-facing default image
                        rotationAlignment="map"
                        pitchAlignment="map"
                    >
                        <div className="relative">
                            <img
                                src="/Truck.png"
                                alt="Driver"
                                className="w-20 h-20 object-contain drop-shadow-2xl" // Slightly larger
                            />
                        </div>
                    </Marker>
                )}

                {/* Route Line */}
                {driverLoc && mapLoaded && (
                    <Source id="route-source" type="geojson" data={routeGeoJSON as any}>
                        <Layer
                            id="route-layer"
                            type="line"
                            layout={{
                                'line-join': 'round',
                                'line-cap': 'round'
                            }}
                            paint={{
                                'line-color': '#F97316', // Orange-500
                                'line-width': 6,
                                'line-opacity': 0.9
                            }}
                        />
                        <Layer
                            id="route-layer-dashed"
                            type="line"
                            paint={{
                                'line-color': '#ffffff',
                                'line-width': 2,
                                'line-opacity': 0.6,
                                'line-dasharray': [2, 2]
                            }}
                        />
                    </Source>
                )}
            </Map>
        </div>
    );
};

export default OrderTrackingMap;

import React, { useState } from 'react';
import { X, Upload, Loader2, AlertCircle, CheckSquare, Square } from 'lucide-react';

interface ReturnOrderModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSubmit: (data: { selectedItems: any[], reason: string; comment: string; images: string[] }) => Promise<void>;
    orderItems: any[];
    orderId: string;
}

const ReturnOrderModal: React.FC<ReturnOrderModalProps> = ({ isOpen, onClose, onSubmit, orderItems, orderId }) => {
    const [reason, setReason] = useState<string>('');
    const [comment, setComment] = useState('');
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [selectedItems, setSelectedItems] = useState<string[]>([]); // Array of product IDs

    // Initialize/Reset
    React.useEffect(() => {
        if (isOpen) {
            setReason('');
            setComment('');
            setError(null);
            // Default select all? Or none? Let's select all for convenience.
            setSelectedItems(orderItems.map(item => item.product?._id || item.product?.id || item.productId || item.product));
        }
    }, [isOpen, orderItems]);

    if (!isOpen) return null;

    const toggleItem = (pId: string) => {
        setSelectedItems(prev => {
            if (prev.includes(pId)) {
                return prev.filter(id => id !== pId);
            } else {
                return [...prev, pId];
            }
        });
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!reason) {
            setError("Please select a reason for return");
            return;
        }
        if (selectedItems.length === 0) {
            setError("Please select at least one item to return");
            return;
        }

        setIsSubmitting(true);
        setError(null);
        try {
            // Filter original items based on selection to pass back full objects
            const itemsToReturn = orderItems.filter(item => {
                const pId = item.product?._id || item.product?.id || item.productId || item.product;
                return selectedItems.includes(pId);
            });

            await onSubmit({ selectedItems: itemsToReturn, reason, comment, images: [] });
            onClose();
        } catch (err: any) {
            setError(err.message || 'Failed to submit return request');
        } finally {
            setIsSubmitting(false);
        }
    };

    const reasons = [
        "Defective/Damaged Product",
        "Wrong Item Received",
        "Item Not as Described",
        "Size/Fit Issues",
        "No Longer Needed",
        "Other"
    ];

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
            <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl animate-in fade-in zoom-in duration-200 flex flex-col max-h-[90vh]">

                {/* Header */}
                <div className="flex items-center justify-between p-6 border-b border-gray-100 flex-shrink-0">
                    <div>
                        <h3 className="text-xl font-bold text-gray-900">Return Order</h3>
                        <p className="text-sm text-gray-500 mt-1">Order #{orderId.slice(-6).toUpperCase()}</p>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
                        <X size={20} className="text-gray-500" />
                    </button>
                </div>

                {/* Scrollable Content */}
                <div className="overflow-y-auto p-6 space-y-6">

                    {/* Error Message */}
                    {error && (
                        <div className="bg-red-50 text-red-600 p-3 rounded-lg text-sm flex items-center gap-2">
                            <AlertCircle size={16} />
                            {error}
                        </div>
                    )}

                    {/* Item Selection */}
                    <div className="space-y-3">
                        <label className="text-sm font-medium text-gray-700 block">Select Items to Return ({selectedItems.length})</label>
                        <div className="border rounded-xl divide-y">
                            {orderItems.map((item) => {
                                const pId = item.product?._id || item.product?.id || item.productId || item.product;
                                const isSelected = selectedItems.includes(pId);
                                return (
                                    <div
                                        key={pId}
                                        onClick={() => toggleItem(pId)}
                                        className={`flex items-center gap-3 p-3 cursor-pointer transition-colors ${isSelected ? 'bg-amber-50/50' : 'hover:bg-gray-50'}`}
                                    >
                                        <div className={`w-5 h-5 rounded border flex items-center justify-center flex-shrink-0 ${isSelected ? 'bg-amber-600 border-amber-600 text-white' : 'border-gray-300 text-transparent'}`}>
                                            <CheckSquare size={14} />
                                        </div>
                                        <div className="flex-1">
                                            <p className="font-medium text-gray-900 text-sm">{item.productName || item.name}</p>
                                            <p className="text-xs text-gray-500">Qty: {item.quantity} • ₹{item.unitPrice}</p>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    </div>

                    {/* Reason Selection */}
                    <div className="space-y-2">
                        <label className="text-sm font-medium text-gray-700">Reason for Return *</label>
                        <div className="space-y-2">
                            {reasons.map((r) => (
                                <label key={r} className="flex items-center gap-3 p-3 border rounded-xl hover:bg-gray-50 cursor-pointer transition-colors">
                                    <input
                                        type="radio"
                                        name="returnReason"
                                        value={r}
                                        checked={reason === r}
                                        onChange={(e) => setReason(e.target.value)}
                                        className="w-4 h-4 text-amber-600 border-gray-300 focus:ring-amber-500"
                                    />
                                    <span className="text-gray-700 text-sm">{r}</span>
                                </label>
                            ))}
                        </div>
                    </div>

                    {/* Comment */}
                    <div className="space-y-2">
                        <label className="text-sm font-medium text-gray-700">
                            Additional Comments (Optional)
                        </label>
                        <textarea
                            value={comment}
                            onChange={(e) => setComment(e.target.value)}
                            className="w-full p-4 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-amber-500/20 focus:border-amber-500 transition-all resize-none h-24 text-sm"
                            placeholder="Please provide more details about the issue..."
                        />
                    </div>
                </div>

                {/* Footer */}
                <div className="p-6 border-t border-gray-100 flex-shrink-0">
                    <button
                        onClick={handleSubmit}
                        disabled={isSubmitting || !reason || selectedItems.length === 0}
                        className="w-full bg-[#D97706] text-white py-4 rounded-xl font-medium hover:bg-[#B45309] transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                    >
                        {isSubmitting ? (
                            <>
                                <Loader2 size={20} className="animate-spin" />
                                Submitting Request...
                            </>
                        ) : (
                            `Return ${selectedItems.length} Item${selectedItems.length !== 1 ? 's' : ''}`
                        )}
                    </button>
                </div>
            </div>
        </div>
    );
};

export default ReturnOrderModal;

'use client';

import React, { useState } from 'react';
import { X, Calendar, Clock, RotateCw } from 'lucide-react';
import { useAuth } from '@/lib/context/AuthContext';
import { sileo } from 'sileo';

interface AutoReorderModalProps {
    product: {
        id: string;
        name: string;
        image?: string;
        minOrder: number;
    };
    isOpen: boolean;
    onClose: () => void;
}

const API_BASE = process.env.NEXT_PUBLIC_API_BASE_URL || 'http://localhost:3001';

export default function AutoReorderModal({ product, isOpen, onClose }: AutoReorderModalProps) {
    const { user, token } = useAuth();

    const [quantity, setQuantity] = useState(product.minOrder || 1);
    const [frequency, setFrequency] = useState('Monthly');
    const [startDate, setStartDate] = useState(new Date().toISOString().split('T')[0]);
    const [preferredTime, setPreferredTime] = useState('09:00');
    const [isSubmitting, setIsSubmitting] = useState(false);

    if (!isOpen) return null;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!token) {
            sileo.error({ title: "Please login to enable auto-reorder" });
            return;
        }

        setIsSubmitting(true);

        try {
            const timezoneOffset = new Date().getTimezoneOffset();

            const payload = {
                userId: user?.id,
                productId: product.id,
                quantity,
                frequency,
                startDate: startDate, // Already YYYY-MM-DD
                preferredTime,
                timezoneOffset,
            };

            const res = await fetch(`${API_BASE}/api/subscriptions`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    // 'Authorization': `Bearer ${token}` // If backend required auth header
                },
                body: JSON.stringify(payload)
            });

            const json = await res.json();

            if (json.success) {
                sileo.success({ title: "Auto-reorder enabled successfully!" });
                onClose();
            } else {
                sileo.error({ title: json.error || "Failed to enable auto-reorder" });
            }

        } catch (err: any) {
            sileo.error({ title: err.message || "Something went wrong" });
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
            <div className="bg-white rounded-2xl w-full max-w-sm shadow-xl overflow-hidden animate-in fade-in zoom-in duration-200">

                {/* Header */}
                <div className="bg-orange-50 p-4 border-b border-orange-100 flex justify-between items-center">
                    <div className="flex items-center gap-2 text-orange-700">
                        <RotateCw size={20} />
                        <h3 className="font-bold">Auto Reorder</h3>
                    </div>
                    <button onClick={onClose} className="text-gray-400 hover:text-gray-600 transition-colors">
                        <X size={20} />
                    </button>
                </div>

                {/* Content */}
                <form onSubmit={handleSubmit} className="p-5 space-y-4">

                    <div className="flex items-center gap-3 mb-4">
                        {product.image && (
                            <img src={product.image} alt={product.name} className="w-12 h-12 object-cover rounded-md border" />
                        )}
                        <div>
                            <p className="font-semibold text-gray-800 line-clamp-1">{product.name}</p>
                            <p className="text-xs text-gray-500">Subscribe & Save time</p>
                        </div>
                    </div>

                    {/* Quantity */}
                    <div>
                        <label className="block text-xs font-semibold text-gray-700 mb-1">Quantity</label>
                        <input
                            type="number"
                            min={1}
                            value={quantity}
                            onChange={(e) => setQuantity(Number(e.target.value))}
                            className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-orange-500 outline-none text-sm"
                        />
                    </div>

                    {/* Frequency */}
                    <div>
                        <label className="block text-xs font-semibold text-gray-700 mb-1">Frequency</label>
                        <div className="flex gap-2">
                            {['Weekly', 'Monthly'].map(f => (
                                <button
                                    key={f}
                                    type="button"
                                    onClick={() => setFrequency(f)}
                                    className={`flex-1 py-2 text-xs font-medium rounded-lg border transition-all ${frequency === f
                                        ? 'bg-orange-600 text-white border-orange-600'
                                        : 'bg-white text-gray-600 border-gray-200 hover:bg-gray-50'
                                        }`}
                                >
                                    {f}
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* Date & Time */}
                    <div className="grid grid-cols-2 gap-3">
                        <div>
                            <label className="block text-xs font-semibold text-gray-700 mb-1">
                                Start Date
                            </label>
                            <div className="relative">
                                <Calendar size={14} className="absolute left-2.5 top-2.5 text-gray-400" />
                                <input
                                    type="date"
                                    min={new Date().toISOString().split('T')[0]}
                                    value={startDate}
                                    onChange={(e) => setStartDate(e.target.value)}
                                    className="w-full pl-8 p-2 border rounded-lg focus:ring-2 focus:ring-orange-500 outline-none text-sm"
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-xs font-semibold text-gray-700 mb-1">Time</label>
                            <div className="relative">
                                <Clock size={14} className="absolute left-2.5 top-2.5 text-gray-400" />
                                <input
                                    type="time"
                                    value={preferredTime}
                                    onChange={(e) => setPreferredTime(e.target.value)}
                                    className="w-full pl-8 p-2 border rounded-lg focus:ring-2 focus:ring-orange-500 outline-none text-sm"
                                />
                            </div>
                        </div>
                    </div>

                    {/* Info Text */}
                    <div className="text-[10px] text-gray-500 bg-gray-50 p-2 rounded border border-gray-100">
                        First order on <strong className="text-gray-700">{new Date(startDate).toLocaleDateString()}</strong> at <strong className="text-gray-700">{preferredTime}</strong>.
                    </div>

                    <button
                        type="submit"
                        disabled={isSubmitting}
                        className="w-full bg-orange-600 hover:bg-orange-700 text-white font-bold py-2.5 rounded-lg text-sm transition-colors disabled:opacity-70 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                    >
                        {isSubmitting ? (
                            <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
                        ) : (
                            <>Enable Auto Reorder</>
                        )}
                    </button>

                </form>
            </div>
        </div>
    );
}

'use client';

import { useEffect, useState } from 'react';
import ProductCard from './ProductCard';
import SkeletonCard from './SkeletonCard';
import { Product } from '@/lib/types/product';
import { useAuth } from '@/lib/context/AuthContext';
import { Sparkles, Loader } from 'lucide-react';

const API_BASE = process.env.NEXT_PUBLIC_API_BASE_URL || 'http://localhost:3001';

export default function FrequentlyBought() {
    const { user, isAuthenticated } = useAuth();
    const [products, setProducts] = useState<Product[]>([]);
    const [loading, setLoading] = useState(true);

    // If we wanted to hide this section if the user isn't logged in, we could return null early.
    // But maybe we want to show generic "Bestsellers" instead?
    // For this task, we'll focus on the user's frequent items as requested.

    useEffect(() => {
        if (!isAuthenticated || !user?.id) {
            setLoading(false);
            return;
        }

        const fetchFrequentItems = async () => {
            try {
                const res = await fetch(`${API_BASE}/api/analytics/frequent-items?userId=${user.id}`);
                if (res.ok) {
                    const json = await res.json();
                    if (json.success && Array.isArray(json.data)) {
                        setProducts(json.data);
                    }
                }
            } catch (err) {
                console.error("Failed to fetch frequent items:", err);
            } finally {
                setLoading(false);
            }
        };

        fetchFrequentItems();
    }, [user?.id, isAuthenticated]);

    if (!isAuthenticated) return null;
    if (!loading && products.length === 0) return null;

    return (
        <div className="mb-8 animate-in fade-in slide-in-from-top-4 duration-500">
            <div className="flex items-center gap-2 mb-4">
                <div className="p-1.5 bg-orange-100 rounded-lg text-orange-600">
                    <Sparkles size={20} />
                </div>
                <h2 className="text-xl font-bold text-gray-900">Your Regulars</h2>
            </div>

            <p className="text-sm text-gray-500 mb-4 -mt-2">Items you buy frequently. Subscribe to save time!</p>

            {loading ? (
                <div className="flex gap-4 overflow-x-auto pb-4 scrollbar-hide snap-x">
                    {Array.from({ length: 4 }).map((_, i) => (
                        <div key={i} className="min-w-[200px] w-[200px] snap-start">
                            <SkeletonCard />
                        </div>
                    ))}
                </div>
            ) : products.length === 0 ? null : (
                <div className="flex gap-4 overflow-x-auto pb-4 scrollbar-hide snap-x">
                    {products.map(product => (
                        <div key={product._id} className="min-w-[200px] w-[200px] snap-start">
                            <ProductCard product={product} />
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
}

'use client';

import { useAuth } from '@/lib/context/AuthContext';
import { Product } from '@/lib/types/product';
import { Star, Plus, Heart, RotateCw } from 'lucide-react';
import Image from 'next/image';
import Link from 'next/link';
import { useEffect, useState, useMemo } from 'react';
import AutoReorderModal from './AutoReorderModal';

interface ProductCardProps {
  product?: Partial<Product> | null;
  initialWishlistState?: boolean;
  onRemove?: (id: string) => void;
}

const API_BASE = process.env.NEXT_PUBLIC_API_BASE_URL;

// Get API base URL with fallback
const getApiBase = () => {
  return process.env.NEXT_PUBLIC_API_BASE_URL || "http://horeca-backend-six.vercel.app";  // backend
};

function mapRawToProduct(raw: any): Product | null {
  if (!raw) return null;
  const id = raw._id ?? raw.id ?? raw.productId;
  if (!id) return null;

  return {
    id: String(id),
    name: raw.name ?? raw.title ?? 'Unnamed product',
    description: raw.description ?? raw.desc ?? '',
    price: typeof raw.price === 'number' ? raw.price : Number(raw.price ?? 0),
    discount: typeof raw.discount === 'number' ? raw.discount : (typeof raw.offerPercentage === 'number' ? raw.offerPercentage : 0),
    image:
      typeof raw.image === 'string'
        ? raw.image
        : Array.isArray(raw.images) && raw.images.length
          ? (raw.images[0].url ?? raw.images[0])
          : '',
    unit: raw.unit ?? 'pcs',
    minOrder: typeof raw.minOrder === 'number' ? raw.minOrder : (raw.minOrder ?? 1),
    rating: typeof raw.rating === 'number' ? raw.rating : (raw.averageRating ?? 0),
    reviews: typeof raw.reviews === 'number' ? raw.reviews : (raw.totalReviews ?? 0),
    category: raw.category ?? raw.categoryName ?? raw.categoryId ?? '',
    badge: raw.badge ?? (raw.isFeatured ? 'Featured' : undefined),
    inStock: typeof raw.inStock === 'boolean' ? raw.inStock : (typeof raw.stockQuantity === 'number' ? raw.stockQuantity > 0 : true),
    stockQuantity: typeof raw.stockQuantity === 'number' ? raw.stockQuantity : undefined,
    ...(raw as any),
  } as Product;
}

export default function ProductCard({ product: incoming, initialWishlistState = false, onRemove }: ProductCardProps) {
  // All state declarations first
  const [isAdding, setIsAdding] = useState(false);
  const [isWishlisting, setIsWishlisting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [wishlistError, setWishlistError] = useState<string | null>(null);
  const [success, setSuccess] = useState(false);
  const [wishlistSuccess, setWishlistSuccess] = useState(false);
  const [isInWishlist, setIsInWishlist] = useState(initialWishlistState);
  const [API_BASE, setApiBase] = useState('');
  const [productState, setProductState] = useState<Product | null>(null);
  const [reviews, setReviews] = useState<any[]>([]);
  const [isReorderModalOpen, setIsReorderModalOpen] = useState(false);
  const { user, token } = useAuth();

  // Helper function defined early
  const looksPartial = (p: Partial<Product> | null | undefined) =>
    !p || !p.id || p.price == null || !p.image;

  // Initialize API base on client side
  useEffect(() => {
    setApiBase(getApiBase());
  }, []);

  // Fetch product data
  useEffect(() => {
    if (!incoming) return;

    const mapped = mapRawToProduct(incoming);
    if (mapped) {
      setProductState(mapped);
    }
  }, [incoming]);


  // Define effectiveProduct using useMemo
  const effectiveProduct = useMemo(() => {
    return (productState ?? (incoming as Product) ?? {
      id: 'unknown',
      name: 'Unnamed product',
      description: '',
      price: 0,
      discount: 0,
      image: '',
      unit: 'pcs',
      minOrder: 1,
      rating: 0,
      reviews: 0,
      category: '',
      badge: undefined,
      inStock: true,
      stockQuantity: undefined,
      // minOrder: 1, // Ensure minOrder is set to default
    }) as Product;
  }, [productState, incoming]);

  // Fetch Reviews specifically for this card to ensure accurate rating
  useEffect(() => {
    if (!effectiveProduct?.id || !API_BASE) return;

    const fetchReviews = async () => {
      try {
        console.log(`⭐ Fetching reviews for product: ${effectiveProduct.id} from ${API_BASE}`);
        const res = await fetch(`${API_BASE}/api/reviews?productId=${effectiveProduct.id}`);
        console.log(`⭐ Fetch status for ${effectiveProduct.id}: ${res.status}`);
        if (res.ok) {
          const data = await res.json();
          console.log(`⭐ Reviews data for ${effectiveProduct.id}:`, data);
          setReviews(data.reviews || []);
        } else {
          console.log(`⭐ Fetch failed for ${effectiveProduct.id}`);
        }
      } catch (e) {
        console.error(`⭐ Error fetching reviews for ${effectiveProduct.id}:`, e);
      }
    };

    fetchReviews();
  }, [effectiveProduct.id, API_BASE]);

  // Check wishlist status - NOW it can use effectiveProduct safely
  useEffect(() => {
    if (!effectiveProduct?.id || !user?.id) return;

    const checkWishlistStatus = async () => {
      if (!token) return;

      try {
        const response = await fetch(`https://horeca-backend-six.vercel.app/api/wishlist/check/${effectiveProduct.id}`, {
          method: "GET",
          headers: {
            "Authorization": `Bearer ${token}`,
            "Accept": "application/json",
          },
        });

        if (response.ok) {
          const data = await response.json();
          setIsInWishlist(data.isInWishlist || false);
        }
      } catch (err) {
        console.error("Failed to check wishlist status:", err);
      }
    };

    checkWishlistStatus();
  }, [effectiveProduct?.id, user?.id, "https://horeca-backend-six.vercel.app"]);

  const [notifySuccess, setNotifySuccess] = useState(false);

  // Notify Me handler
  const handleNotifyMe = (e: React.MouseEvent) => {
    e.stopPropagation();
    e.preventDefault();
    setNotifySuccess(true);
    setTimeout(() => setNotifySuccess(false), 3000);
  };

  // Cart handler
  const handleAddToCart = async (e: React.MouseEvent) => {
    e.stopPropagation();
    e.preventDefault();

    if (!effectiveProduct?.id || isAdding) return;

    setIsAdding(true);
    setError(null);
    setSuccess(false);

    try {

      if (!token) {
        throw new Error("Please log in to add items to your cart.");
      }

      const payload = {
        userId: user?.id,                 // ✅ BACKEND EXPECTS THIS
        productId: effectiveProduct.id,   // ✅ BACKEND EXPECTS THIS
        quantity: effectiveProduct.minOrder,
      };

      const response = await fetch(`https://horeca-backend-six.vercel.app/api/cart`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${token}`,
        },
        body: JSON.stringify(payload),
      });

      if (!response.ok) {
        const err = await response.json().catch(() => null);
        console.error("🔴 FULL BACKEND ERROR:", err);
        throw new Error(err?.message || err?.error || "Failed to add to cart");
      }

      const result = await response.json();
      window.dispatchEvent(new Event("cart-updated"));
      setSuccess(true);

    } catch (err: any) {
      setError(err?.message || "Failed to add to cart.");
      setTimeout(() => setError(null), 4000);
    } finally {
      setIsAdding(false);
      setTimeout(() => setSuccess(false), 2000);
    }
  };

  // Wishlist handler
  const handleWishlistToggle = async (e: React.MouseEvent) => {
    e.stopPropagation();
    e.preventDefault();

    if (!effectiveProduct?.id || isWishlisting) return;

    setIsWishlisting(true);
    setWishlistError(null);
    setWishlistSuccess(false);

    try {
      if (!token) {
        throw new Error("Please log in to manage your wishlist.");
      }

      const payload = {
        productId: effectiveProduct.id,
        userId: user?.id || '',
      };

      const method = isInWishlist ? "DELETE" : "POST";
      // FIX: use base URL for DELETE too, as /:id path returns 405 Method Not Allowed
      const endpoint = `https://horeca-backend-six.vercel.app/api/wishlist`;

      console.log(`💟 Wishlist Request: ${method} to ${endpoint}`);
      console.log("Payload:", payload);

      const response = await fetch(endpoint, {
        method: method,
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${token}`,
        },
        body: JSON.stringify(payload),
      });

      if (!response.ok) {
        const err = await response.json().catch(() => null);
        console.error("🔴 WISHLIST BACKEND ERROR:", err);
        throw new Error(err?.message || err?.error ||
          (isInWishlist ? "Failed to remove from wishlist" : "Failed to add to wishlist"));
      }

      const result = await response.json();

      // Toggle the wishlist status
      setIsInWishlist(!isInWishlist);
      setWishlistSuccess(true);

      // Notify Header to update count
      window.dispatchEvent(new Event("wishlist-updated"));

      // Notify parent if removal happened and onRemove prop exists
      if (isInWishlist && onRemove && effectiveProduct.id) {
        onRemove(effectiveProduct.id);
      }

    } catch (err: any) {
      setWishlistError(err?.message ||
        (isInWishlist ? "Failed to remove from wishlist" : "Failed to add to wishlist"));
      setTimeout(() => setWishlistError(null), 4000);
    } finally {
      setIsWishlisting(false);
      setTimeout(() => setWishlistSuccess(false), 2000);
    }
  };

  // Helper functions for rendering
  const getBadgeColor = (badge: string | undefined) => {
    switch (badge) {
      case 'Bestseller':
        return 'bg-[#D97706] text-white';
      case 'New':
        return 'bg-[#D97706] text-white';
      case 'In Stock':
        return 'bg-emerald-500 text-white';
      case 'Premium':
        return 'bg-purple-500 text-white';
      case 'Sale':
        return 'bg-red-500 text-white';
      default:
        return 'bg-gray-500 text-white';
    }
  };

  const discountedPrice = effectiveProduct.discount
    ? (effectiveProduct.price - (effectiveProduct.price * effectiveProduct.discount) / 100)
    : null;

  const computeCategoryLabel = (cat: any) => {
    if (!cat) return '';
    if (typeof cat === 'object') {
      return String(cat.name ?? cat.title ?? cat.slug ?? '').trim();
    }
    const s = String(cat).trim();
    const isHex24 = /^[0-9a-fA-F]{24}$/.test(s);
    const isUuid = /^[0-9a-fA-F-]{36}$/.test(s);
    if (isHex24 || isUuid) return '';
    return s;
  };

  const categoryLabel = computeCategoryLabel(effectiveProduct.category);

  // Dynamic Rating Calculation
  const dynamicRating = reviews.length > 0
    ? Number((reviews.reduce((acc: any, r: any) => acc + (r.rating || 0), 0) / reviews.length).toFixed(1))
    : effectiveProduct.rating;

  const dynamicCount = reviews.length > 0 ? reviews.length : effectiveProduct.reviews;

  // Render component
  return (
    <div className="group bg-white rounded-xl overflow-hidden hover:shadow-md transition-shadow duration-300 relative border border-transparent hover:border-gray-100">
      {/* Error Messages */}
      {error && (
        <div className="absolute top-2 left-2 right-2 bg-red-100 text-red-700 text-xs p-2 rounded-md z-20 animate-fade-in whitespace-pre-line">
          {error}
        </div>
      )}

      {wishlistError && (
        <div className="absolute top-2 left-2 right-2 bg-red-100 text-red-700 text-xs p-2 rounded-md z-20 animate-fade-in whitespace-pre-line">
          {wishlistError}
        </div>
      )}

      {success && (
        <div className="pointer-events-none absolute top-2 left-2 right-2 bg-green-100 text-green-700 text-xs p-2 rounded-md z-20">
          Added to cart!
        </div>
      )}

      {notifySuccess && (
        <div className="pointer-events-none absolute top-2 left-2 right-2 bg-blue-100 text-blue-700 text-xs p-2 rounded-md z-20">
          You will be notified!
        </div>
      )}

      {/* Product Image Area */}
      <div className="relative aspect-[4/3] bg-[#F9F9F9] overflow-hidden">
        <Link href={`/products/${effectiveProduct.id}`} className="block w-full h-full relative">
          {(() => {
            const rawImage = (effectiveProduct.image ?? '').trim();
            let src = '/images/placeholder.png';

            if (rawImage) {
              if (rawImage.startsWith('http://') || rawImage.startsWith('https://') || rawImage.startsWith('//')) {
                src = rawImage;
              } else {
                const filename = rawImage.replace(/^\/+/, '');
                src = `/images/products/${filename}`;
              }
            }

            const isExternal = src.startsWith('http') || src.startsWith('//');

            return (
              <Image
                src={src}
                alt={effectiveProduct.name}
                fill
                sizes="(max-width: 768px) 50vw, (max-width: 1024px) 33vw, 25vw"
                className="object-cover group-hover:scale-105 transition-transform duration-500 rounded-t-xl"
                unoptimized={isExternal}
                priority={false}
              />
            );
          })()}
        </Link>

        {/* Out of Stock Overlay */}
        {!effectiveProduct.inStock && (
          <div className="absolute inset-0 bg-white/60 backdrop-blur-[2px] z-10 flex items-center justify-center">
            <span className="bg-gray-900 text-white text-xs font-bold px-3 py-1 rounded-full uppercase tracking-wider">
              Out of Stock
            </span>
          </div>
        )}

        {/* Low Stock Warning */}
        {effectiveProduct.inStock && (effectiveProduct.stockQuantity !== undefined && effectiveProduct.stockQuantity <= 10) && (
          <div className="absolute bottom-0 left-0 right-0 bg-red-50/90 backdrop-blur-sm border-t border-red-100 p-1.5 z-10 flex justify-center">
            <span className="text-[10px] font-bold text-red-600 flex items-center gap-1">
              ⚠️ Only {effectiveProduct.stockQuantity} left!
            </span>
          </div>
        )}

        {/* Wishlist Button - Top Right */}
        <div className="absolute top-3 right-3 flex flex-col gap-2 z-10">
          <button
            onClick={handleWishlistToggle}
            disabled={isWishlisting || !API_BASE}
            className="p-1.5 rounded-full bg-white/80 hover:bg-white text-gray-400 hover:text-red-500 transition-colors shadow-sm"
          >
            <Heart
              size={18}
              className={isInWishlist ? "fill-red-500 text-red-500" : ""}
            />
          </button>
          <button
            onClick={(e) => {
              e.preventDefault();
              setIsReorderModalOpen(true);
            }}
            className="p-1.5 rounded-full bg-white/80 hover:bg-white text-gray-400 hover:text-orange-600 transition-colors shadow-sm"
            title="Auto Reorder"
          >
            <RotateCw size={18} />
          </button>
        </div>
      </div>

      {/* Product Info */}
      <div className="p-3">
        {/* Veg Indicator */}
        <div className="mb-1">
          <div className="border border-green-600 p-[2px] w-4 h-4 flex items-center justify-center rounded-[2px]">
            <div className="w-2 h-2 bg-green-600 rounded-full"></div>
          </div>
        </div>

        {/* Title */}
        <Link href={`/products/${effectiveProduct.id}`}>
          <h3 className="font-bold text-gray-900 text-[15px] mb-1 leading-tight line-clamp-2 min-h-[40px]">
            {effectiveProduct.name}
          </h3>
        </Link>

        {/* Rating */}
        <div className="flex items-center gap-1 mb-2">
          <div className={`flex items-center px-1.5 py-0.5 rounded text-[10px] font-bold ${dynamicRating > 0 ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-500'}`}>
            {dynamicRating > 0 ? dynamicRating : 'New'}
            {dynamicRating > 0 && <Star size={10} className="fill-green-700 ml-0.5" />}
          </div>
          {dynamicCount > 0 && (
            <span className="text-xs text-gray-400">({dynamicCount} reviews)</span>
          )}
        </div>

        {/* Price and Add Button */}
        <div className="flex items-center justify-between mt-auto">
          <div className="flex flex-col">
            <span className="text-sm font-bold text-gray-900">
              ₹{discountedPrice ? discountedPrice.toFixed(0) : effectiveProduct.price}
              <span className="text-gray-500 font-normal ml-1">/ {effectiveProduct.unit}</span>
            </span>
            {discountedPrice && (
              <span className="text-xs text-gray-400 line-through">₹{effectiveProduct.price}</span>
            )}
          </div>

          <button
            onClick={effectiveProduct.inStock ? handleAddToCart : handleNotifyMe}
            disabled={isAdding || !API_BASE}
            className={`px-4 py-1.5 rounded border text-xs font-bold transition-all uppercase z-20
              ${!effectiveProduct.inStock
                ? 'bg-orange-50 border-orange-200 text-[#D97706] hover:bg-orange-100'
                : isAdding
                  ? 'bg-orange-50 border-orange-500 text-orange-600'
                  : 'bg-white border-orange-400 text-orange-500 hover:bg-orange-50'
              }`}
          >
            {effectiveProduct.inStock ? (isAdding ? 'ADD...' : 'ADD +') : 'Notify Me'}
          </button>
        </div>
      </div>

      {effectiveProduct?.id && (
        <AutoReorderModal
          product={{
            id: effectiveProduct.id,
            name: effectiveProduct.name,
            image: effectiveProduct.image,
            minOrder: effectiveProduct.minOrder
          }}
          isOpen={isReorderModalOpen}
          onClose={() => setIsReorderModalOpen(false)}
        />
      )}
    </div >
  );
}

'use client';

import { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Product } from '@/lib/types/product';
import ProductImageGallery from './ProductImageGallery';
import ProductReviews from './ProductReviews';
import ReviewFormModal from './ReviewFormModal'; // Added
import RelatedProducts from './RelatedProducts';
import { Review } from '@/lib/types/product'; // Added
import {
    Star,
    Minus,
    Plus,
    ShoppingCart,
    Heart,
    Share2,
    Truck,
    Shield,
    RotateCcw,
    Award,
} from 'lucide-react';
import Link from 'next/link';
import { useCart } from '@/lib/context/CartContext';
import { useAuth } from '@/lib/context/AuthContext';
import { useMemo } from 'react';

interface ProductDetailClientProps {
    product?: Product; // made optional so the component can fetch when not provided
    relatedProducts?: Product[];
}

const API_BASE = (process.env.NEXT_PUBLIC_API_BASE_URL || 'https://horeca-backend-six.vercel.app').trim();

export default function ProductDetailClient({
    product: initialProduct,
    relatedProducts: initialRelated = [],
}: ProductDetailClientProps) {
    const { addItem } = useCart();
    const [product, setProduct] = useState<Product | null>(initialProduct ?? null);
    const [relatedProducts, setRelatedProducts] = useState<Product[]>(initialRelated);
    const [isAdding, setIsAdding] = useState(false);
    const [quantity, setQuantity] = useState<number>(initialProduct?.minOrder ?? 1);
    const [activeTab, setActiveTab] = useState<'description' | 'specifications' | 'reviews'>('description');
    const [isWishlisting, setIsWishlisting] = useState(false);
    const [isInWishlist, setIsInWishlist] = useState(false);
    const [wishlistError, setWishlistError] = useState<string | null>(null);
    const { user, token } = useAuth();
    const [shareMessage, setShareMessage] = useState<string | null>(null);

    // Reviews State
    const [reviews, setReviews] = useState<Review[]>([]);


    const averageRating = useMemo(() => {
        if (!reviews.length) return 0;
        const sum = reviews.reduce((acc, r) => acc + r.rating, 0);
        return Number((sum / reviews.length).toFixed(1));
    }, [reviews]);


    const [isReviewFormOpen, setIsReviewFormOpen] = useState(false);
    const [reviewsLoading, setReviewsLoading] = useState(false);


    const handleShare = async () => {
        if (!product) return;

        const shareUrl =
            typeof window !== "undefined"
                ? window.location.href
                : "";

        try {
            // ✅ Use native share if available (mobile, modern browsers)
            if (navigator.share) {
                await navigator.share({
                    title: product.name,
                    text: `Check out this product: ${product.name}`,
                    url: shareUrl,
                });
                setShareMessage("Product shared successfully!");
            } else {
                // 🧠 Fallback: copy to clipboard
                await navigator.clipboard.writeText(shareUrl);
                setShareMessage("Product link copied to clipboard!");
            }
        } catch (err) {
            console.error("Share failed:", err);
            setShareMessage("Failed to share product.");
        } finally {
            setTimeout(() => setShareMessage(null), 3000);
        }
    };


    useEffect(() => {
        if (!product?.id) return;

        const checkWishlist = async () => {
            if (!token) return;

            try {
                const base =
                    (process.env.NEXT_PUBLIC_API_BASE_URL ||
                        "https://horeca-backend-six.vercel.app").replace(/\/$/, "");

                const res = await fetch(
                    `${base}/api/wishlist/check/${product.id}`,
                    {
                        headers: {
                            Authorization: `Bearer ${token}`,
                            Accept: "application/json",
                        },
                    }
                );

                if (!res.ok) return;

                const data = await res.json();
                setIsInWishlist(Boolean(data?.isInWishlist));
            } catch (err) {
                console.error("Wishlist check failed:", err);
            }
        };

        checkWishlist();
    }, [product?.id]);


    const handleWishlistToggle = async () => {
        if (!product?.id || isWishlisting) return;

        setIsWishlisting(true);
        setWishlistError(null);

        try {
            if (!token) {
                throw new Error("Please log in to manage your wishlist.");
            }

            // ✅ DEFINE BASE HERE
            const base =
                (process.env.NEXT_PUBLIC_API_BASE_URL ||
                    "https://horeca-backend-six.vercel.app").replace(/\/$/, "");

            // ✅ FIX: Use base URL for DELETE too, as /:id returns 405 Method Not Allowed
            const endpoint = `${base}/api/wishlist`;

            const res = await fetch(endpoint, {
                method: isInWishlist ? "DELETE" : "POST",
                headers: {
                    "Content-Type": "application/json",
                    Authorization: `Bearer ${token}`,
                },
                body: JSON.stringify({
                    productId: product.id,
                    userId: user?.id || user?.id,
                }),
            });

            if (!res.ok) {
                const err = await res.json().catch(() => null);
                console.error("WISHLIST ERROR:", err);
                throw new Error(err?.message || "Wishlist update failed");
            }

            setIsInWishlist((prev) => !prev);
            // Notify Header
            window.dispatchEvent(new Event("wishlist-updated"));
        } catch (err: any) {
            setWishlistError(err.message || "Wishlist error");
            setTimeout(() => setWishlistError(null), 3000);
        } finally {
            setIsWishlisting(false);
        }
    };






    // helper builder & mapper (same defensive approach)
    const buildUrl = (path: string) => {
        const base = API_BASE.replace(/\/+$/, '');
        const raw = base ? `${base}/${path.replace(/^\/+/, '')}` : `/${path.replace(/^\/+/, '')}`;
        return raw.replace(/([^:]\/)\/+/g, '$1');
    };

    const mapProduct = (raw: any): Product | null => {
        if (!raw) return null;
        const id = raw._id ?? raw.id ?? raw.productId ?? String(raw.sku ?? '');
        if (!id) return null;
        return {
            id: String(id),
            name: raw.name ?? raw.title ?? 'Unnamed product',
            description: raw.description ?? raw.desc ?? '',
            price: typeof raw.price === 'number' ? raw.price : Number(raw.price ?? 0),
            discount: typeof raw.discount === 'number' ? raw.discount : (typeof raw.offerPercentage === 'number' ? raw.offerPercentage : 0),
            image: (raw.image && typeof raw.image === 'string') ? raw.image : (Array.isArray(raw.images) && raw.images[0] ? (raw.images[0].url ?? raw.images[0]) : ''),
            unit: raw.unit ?? 'pcs',
            minOrder: typeof raw.minOrder === 'number' ? raw.minOrder : (raw.minOrder ?? 1),
            rating: typeof raw.rating === 'number' ? raw.rating : (raw.averageRating ?? 0),
            reviews: typeof raw.reviews === 'number' ? raw.reviews : (raw.totalReviews ?? 0),
            category: raw.category ?? raw.categoryName ?? raw.categoryId ?? '',
            badge: raw.badge ?? (raw.isFeatured ? 'Featured' : undefined),
            inStock: typeof raw.inStock === 'boolean' ? raw.inStock : (typeof raw.stockQuantity === 'number' ? raw.stockQuantity > 0 : true),
            stockQuantity: typeof raw.stockQuantity === 'number' ? raw.stockQuantity : undefined,
            ...(raw as any),
        } as Product;
    };

    // fetch single product when initialProduct not provided
    useEffect(() => {
        if (product) {
            // set initial quantity if product arrives
            setQuantity(product.minOrder ?? 1);
            return;
        }

        // try to extract product id from URL if we are on /products/:id
        let productId: string | null = null;
        try {
            const path = typeof window !== 'undefined' ? window.location.pathname : '';
            const match = path.match(/\/products\/([^/]+)/);
            if (match && match[1]) productId = decodeURIComponent(match[1]);
        } catch (e) {
            // ignore
        }
        if (!productId) return;

        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 10000);

        (async () => {
            try {
                const url = buildUrl(`api/products/${encodeURIComponent(productId)}`);
                const res = await fetch(url, { signal: controller.signal, headers: { Accept: 'application/json' } });
                if (!res.ok) {
                    let msg = '';
                    try {
                        const b = await res.json();
                        msg = b?.message ? ` — ${b.message}` : '';
                    } catch { }
                    throw new Error(`Failed to fetch product (status ${res.status})${msg}`);
                }
                const ct = res.headers.get('content-type') ?? '';
                if (!ct.includes('application/json')) throw new Error('Invalid response: expected JSON');
                const json = await res.json();
                const raw = json?.data ?? json?.product ?? json;
                const mapped = mapProduct(raw);
                if (mapped) {
                    setProduct(mapped);
                    setQuantity(mapped.minOrder ?? 1);
                } else {
                    console.warn('[ProductDetailClient] product shape invalid', raw);
                }
            } catch (err: any) {
                if (err?.name === 'AbortError') {
                    console.debug('[ProductDetailClient] product fetch aborted');
                } else {
                    console.error('[ProductDetailClient] error fetching product', err);
                }
            } finally {
                clearTimeout(timeoutId);
            }
        })();

        return () => {
            controller.abort();
            clearTimeout(timeoutId);
        };
        // we want to run once on mount if no product passed
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    // fetch related products (simple approach by category) when we have the product and no initial related products
    useEffect(() => {
        if (!product) return;
        if (initialRelated && initialRelated.length > 0) return;

        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 10000);

        (async () => {
            try {
                // naive related fetch: by category with limit
                const urlObj = new URL(buildUrl('api/products'), typeof window !== 'undefined' ? window.location.origin : 'http://localhost');
                if (product.category) urlObj.searchParams.set('category', product.category);
                urlObj.searchParams.set('limit', '6');

                const res = await fetch(urlObj.toString(), { signal: controller.signal, headers: { Accept: 'application/json' } });
                if (!res.ok) return;
                const json = await res.json();
                let list: any[] = [];

                if (Array.isArray(json)) {
                    list = json;
                } else if (Array.isArray(json?.data)) {
                    list = json.data;
                } else if (Array.isArray(json?.products)) {
                    list = json.products;
                } else if (Array.isArray(json?.data?.products)) {
                    list = json.data.products;
                } else {
                    console.warn(
                        "[ProductDetailClient] Related products response is not an array:",
                        json
                    );
                    list = [];
                }

                const mapped = list
                    .map(mapProduct)
                    .filter(Boolean) as Product[];


                // remove the current product from related list if present
                const filtered = mapped.filter((p) => p.id !== product.id).slice(0, 6);
                setRelatedProducts(filtered);
            } catch (err: any) {
                if (err?.name === 'AbortError') return;
                console.error('[ProductDetailClient] related products fetch failed', err);
            } finally {
                clearTimeout(timeoutId);
            }
        })();

        return () => {
            controller.abort();
            clearTimeout(timeoutId);
        };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [product?.id]);

    // Fetch Reviews
    const fetchReviews = async () => {
        if (!product?.id) return;

        setReviewsLoading(true);
        try {
            const res = await fetch(
                `${API_BASE.replace(/\/$/, '')}/api/reviews?productId=${product.id}`,
                { headers: { Accept: 'application/json' } }
            );

            if (!res.ok) throw new Error("Failed to fetch reviews");

            const json = await res.json();
            setReviews(json.reviews || []);
        } catch (err) {
            console.error("Fetch reviews failed:", err);
        } finally {
            setReviewsLoading(false);
        }
    };

    useEffect(() => {
        fetchReviews();
    }, [product?.id]);


    const handleReviewSubmit = async (data: { rating: number; comment: string; images: string[] }) => {
        if (!product?.id) return;

        // Check auth
        if (!token) {
            // You might want to show a toast or alert here
            alert("Please log in to submit a review.");
            return;
        }

        const payload = {
            productId: product.id,
            rating: data.rating,
            comment: data.comment,
            images: data.images
        };

        const base = API_BASE.replace(/\/$/, "");
        const res = await fetch(`${base}/api/reviews`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${token}`
            },
            body: JSON.stringify(payload)
        });

        if (!res.ok) {
            const err = await res.json();
            throw new Error(err.message || "Failed to submit review");
        }

        // Refresh reviews
        fetchReviews();
    };

    const handleAddToCart = () => {
        if (!product) return;
        setIsAdding(true);
        addItem(product, quantity);
        setTimeout(() => {
            setIsAdding(false);
        }, 1000);
    };

    const incrementQuantity = () => setQuantity((prev) => prev + 1);
    const decrementQuantity = () => setQuantity((prev) => Math.max(product?.minOrder ?? 1, prev - 1));

    const discountedPrice = product?.discount
        ? (product.price - (product.price * product.discount) / 100)
        : null;

    const totalPrice = ((discountedPrice ?? product?.price) ?? 0) * quantity;

    // fallback while loading product
    if (!product) {
        return (
            <div className="min-h-screen bg-[#FAFAF7]">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
                    <div className="text-center py-24">
                        <p className="text-gray-500">Loading product...</p>
                    </div>
                </div>
            </div>
        );
    }

    // Reviews now fetched from API


    return (
        <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="min-h-screen bg-[#FAFAF7]"
        >
            {/* Breadcrumb */}
            <div className="bg-white border-b border-gray-100">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
                    <nav className="flex items-center gap-2 text-sm text-gray-600">
                        <Link href="/" className="hover:text-[#D97706] transition-colors">Home</Link>
                        <span>/</span>
                        <a href="/products" className="hover:text-[#D97706] transition-colors">Products</a>
                        <span>/</span>
                        <a href={`/products?category=${product.category}`} className="hover:text-[#D97706] transition-colors">
                            {product.category}
                        </a>
                        <span>/</span>
                        <span className="text-[#111827] font-medium">{product.name}</span>
                    </nav>
                </div>
            </div>

            {/* Product Details */}
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
                <div className="grid lg:grid-cols-2 gap-12 mb-12">
                    {/* Left: Image Gallery */}
                    <motion.div
                        initial={{ opacity: 0, x: -50 }}
                        animate={{ opacity: 1, x: 0 }}
                        transition={{ duration: 0.5, ease: "easeOut" }}
                    >
                        <ProductImageGallery
                            productName={product.name}
                            mainImage={product.image}
                            images={[product.image, product.image, product.image]}
                        />
                    </motion.div>

                    {/* Right: Product Info */}
                    <motion.div
                        className="space-y-6"
                        initial={{ opacity: 0, x: 50 }}
                        animate={{ opacity: 1, x: 0 }}
                        transition={{ duration: 0.5, ease: "easeOut", delay: 0.2 }}
                    >
                        {/* Category & Badge */}
                        <div className="flex items-center gap-3">
                            <span className="text-sm text-gray-600">{product.category}</span>
                            {product.badge && (
                                <span className={`px-3 py-1 rounded-full text-xs font-medium ${product.badge === 'Bestseller' ? 'bg-[#D97706] text-white' :
                                    product.badge === 'New' ? 'bg-[#D97706] text-white' :
                                        product.badge === 'Premium' ? 'bg-purple-500 text-white' :
                                            'bg-emerald-500 text-white'
                                    }`}>
                                    {product.badge}
                                </span>
                            )}
                        </div>

                        {/* Product Name */}
                        <h1 className="text-3xl font-bold text-gray-900 tracking-tight">
                            {product.name}
                        </h1>

                        {/* Rating */}
                        <div className="flex items-center gap-4">
                            <div className="flex items-center gap-2">
                                <div className="flex items-center gap-1">
                                    {[...Array(5)].map((_, i) => (
                                        <Star
                                            key={i}
                                            size={18}
                                            className={`${i < Math.floor(averageRating || 0)
                                                ? 'fill-[#FFB800] text-[#FFB800]'
                                                : 'text-gray-300'
                                                }`}
                                        />
                                    ))}
                                </div>
                                {/* Dynamically calculated average rating */}
                                <span className="font-semibold text-[#111827]">{averageRating || 0}</span>
                            </div>
                            {/* Actual fetched review count */}
                            <span className="text-gray-600">({reviews.length} reviews)</span>
                        </div>

                        {/* Price */}
                        <div className="py-4 border-y border-gray-200">
                            <div className="flex items-baseline gap-3">
                                {discountedPrice ? (
                                    <>
                                        <span className="text-4xl font-bold text-[#D97706]">
                                            ₹{discountedPrice.toFixed(0)}
                                        </span>
                                        <span className="text-xl text-gray-400 line-through">
                                            ₹{product.price}
                                        </span>
                                        <span className="text-sm bg-red-500 text-white px-2 py-1 rounded-full font-semibold">
                                            Save {product.discount}%
                                        </span>
                                    </>
                                ) : (
                                    <span className="text-4xl font-bold text-[#111827]">
                                        ₹{product.price}
                                    </span>
                                )}
                                <span className="text-gray-600">/ {product.unit}</span>
                            </div>
                            <p className="text-sm text-gray-600 mt-2">
                                Minimum Order: {product.minOrder} {product.unit}
                            </p>

                            {/* Low Stock Warning */}
                            {product.inStock && product.stockQuantity !== undefined && product.stockQuantity <= 10 && (
                                <div className="mt-3 inline-flex items-center gap-2 bg-red-50 text-red-700 px-3 py-1.5 rounded-lg text-sm font-medium border border-red-100">
                                    ⚠️ Only {product.stockQuantity} left in stock!
                                </div>
                            )}
                        </div>

                        {/* Description */}
                        <div>
                            <p className="text-gray-700 leading-relaxed">
                                {product.description}
                            </p>
                        </div>

                        {/* Quantity Selector */}
                        <div>
                            <label className="block text-sm font-medium text-[#111827] mb-2">
                                Quantity
                            </label>
                            <div className="flex items-center gap-4">
                                <div className="flex items-center border border-gray-300 rounded-full">
                                    <button
                                        onClick={decrementQuantity}
                                        className="p-3 hover:bg-gray-100 transition-colors rounded-l-full"
                                        disabled={quantity <= product.minOrder}
                                    >
                                        <Minus size={18} />
                                    </button>
                                    <span className="px-6 font-semibold">{quantity}</span>
                                    <button
                                        onClick={incrementQuantity}
                                        className="p-3 hover:bg-gray-100 transition-colors rounded-r-full"
                                    >
                                        <Plus size={18} />
                                    </button>
                                </div>
                                <span className="text-gray-600">
                                    Total: <span className="font-bold text-[#111827]">₹{totalPrice.toFixed(0)}</span>
                                </span>
                            </div>
                        </div>

                        {/* Action Buttons */}
                        <div className="flex gap-3">
                            {product.inStock ? (
                                <button
                                    onClick={handleAddToCart}
                                    disabled={isAdding}
                                    className={`flex-1 py-4 px-6 rounded-xl border-2 font-bold transition-all shadow-sm hover:shadow-md flex items-center justify-center gap-2 uppercase tracking-wide
                                    ${isAdding
                                            ? 'bg-orange-50 border-[#D97706] text-[#D97706]'
                                            : 'bg-white border-[#D97706] text-[#D97706] hover:bg-orange-50'
                                        }`}
                                >
                                    <ShoppingCart size={20} strokeWidth={2.5} />
                                    {isAdding ? 'Adding...' : 'Add to Cart'}
                                </button>
                            ) : (
                                <div className="flex-1 py-4 px-6 rounded-xl border-2 border-gray-200 bg-gray-50 text-red-500 font-bold uppercase tracking-wide flex items-center justify-center cursor-not-allowed">
                                    Out of Stock
                                </div>
                            )}

                            <button
                                onClick={handleWishlistToggle}
                                disabled={isWishlisting}
                                title={isInWishlist ? "Remove from wishlist" : "Add to wishlist"}
                                className={`p-4 border-2 rounded-xl transition-all ${isInWishlist
                                    ? "border-red-500 text-red-500 bg-red-50"
                                    : "border-gray-200 hover:border-[#D97706] hover:text-[#D97706] text-gray-400"
                                    } disabled:opacity-50`}
                            >
                                {isWishlisting ? (
                                    <span className="inline-block h-5 w-5 border-2 border-current border-t-transparent rounded-full animate-spin" />
                                ) : (
                                    <Heart
                                        size={20}
                                        className={isInWishlist ? "fill-current" : ""}
                                        strokeWidth={2}
                                    />
                                )}
                            </button>

                            <button
                                onClick={handleShare}
                                title="Share product"
                                className="p-4 border-2 border-gray-200 rounded-xl hover:border-[#D97706] hover:text-[#D97706] text-gray-400 transition-all"
                            >
                                <Share2 size={20} strokeWidth={2} />
                            </button>

                        </div>

                        {/* Features */}
                        <div className="grid grid-cols-2 gap-4 pt-6">
                            <div className="flex items-start gap-3">
                                <div className="bg-orange-50 p-2.5 rounded-lg text-[#D97706]">
                                    <Truck size={22} />
                                </div>
                                <div>
                                    <h4 className="font-bold text-gray-900 text-sm">Fast Delivery</h4>
                                    <p className="text-xs text-gray-500">2-3 business days</p>
                                </div>
                            </div>
                            <div className="flex items-start gap-3">
                                <div className="bg-orange-50 p-2.5 rounded-lg text-[#D97706]">
                                    <Shield size={22} />
                                </div>
                                <div>
                                    <h4 className="font-bold text-gray-900 text-sm">Quality Assured</h4>
                                    <p className="text-xs text-gray-500">100% authentic</p>
                                </div>
                            </div>
                            <div className="flex items-start gap-3">
                                <div className="bg-orange-50 p-2.5 rounded-lg text-[#D97706]">
                                    <RotateCcw size={22} />
                                </div>
                                <div>
                                    <h4 className="font-bold text-gray-900 text-sm">Easy Returns</h4>
                                    <p className="text-xs text-gray-500">7-day return policy</p>
                                </div>
                            </div>
                            <div className="flex items-start gap-3">
                                <div className="bg-orange-50 p-2.5 rounded-lg text-[#D97706]">
                                    <Award size={22} />
                                </div>
                                <div>
                                    <h4 className="font-bold text-gray-900 text-sm">Verified Seller</h4>
                                    <p className="text-xs text-gray-500">Trusted supplier</p>
                                </div>
                            </div>
                        </div>
                    </motion.div>
                </div>

                {/* Tabs Section */}
                <motion.div
                    className="bg-white rounded-2xl soft-shadow mb-12"
                    initial={{ opacity: 0, y: 30 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    transition={{ duration: 0.6 }}
                >
                    {/* Tab Headers */}
                    <div className="border-b border-gray-200">
                        <div className="flex gap-8 px-8">
                            <button
                                onClick={() => setActiveTab('description')}
                                className={`py-4 font-medium transition-colors relative ${activeTab === 'description' ? 'text-[#D97706]' : 'text-gray-600 hover:text-[#D97706]'
                                    }`}
                            >
                                Description
                                {activeTab === 'description' && <motion.div layoutId="activeTab" className="absolute bottom-0 left-0 right-0 h-0.5 bg-[#D97706]" />}
                            </button>
                            <button
                                onClick={() => setActiveTab('specifications')}
                                className={`py-4 font-medium transition-colors relative ${activeTab === 'specifications' ? 'text-[#D97706]' : 'text-gray-600 hover:text-[#D97706]'
                                    }`}
                            >
                                Specifications
                                {activeTab === 'specifications' && <motion.div layoutId="activeTab" className="absolute bottom-0 left-0 right-0 h-0.5 bg-[#D97706]" />}
                            </button>
                            <button
                                onClick={() => setActiveTab('reviews')}
                                className={`py-4 font-medium transition-colors relative ${activeTab === 'reviews' ? 'text-[#D97706]' : 'text-gray-600 hover:text-[#D97706]'
                                    }`}
                            >
                                Reviews ({reviews.length})
                                {activeTab === 'reviews' && <motion.div layoutId="activeTab" className="absolute bottom-0 left-0 right-0 h-0.5 bg-[#D97706]" />}
                            </button>
                        </div>
                    </div>

                    {/* Tab Content */}
                    <div className="p-8">
                        {activeTab === 'description' && (
                            <div className="prose max-w-none animate-in fade-in duration-300">
                                <h3 className="text-xl font-medium text-[#111827] mb-4">Product Description</h3>
                                <p className="text-gray-700 leading-relaxed mb-4">{product.description}</p>
                                <h4 className="text-lg font-medium text-[#111827] mb-3">Features:</h4>
                                <ul className="space-y-2 text-gray-700">
                                    <li>• Premium quality ingredients for professional use</li>
                                    <li>• Consistent texture and flavor in every batch</li>
                                    <li>• Suitable for all types of baking applications</li>
                                    <li>• Long shelf life with proper storage</li>
                                    <li>• Food-grade packaging for freshness</li>
                                </ul>
                            </div>
                        )}

                        {activeTab === 'specifications' && (
                            <div className="animate-in fade-in duration-300">
                                <h3 className="text-xl font-medium text-[#111827] mb-6">Product Specifications</h3>
                                <div className="grid md:grid-cols-2 gap-x-12 gap-y-4">
                                    {(product?.specifications || [
                                        // Fallback if null (though page.tsx handles this)
                                        { name: "Category", value: product?.category || '-' },
                                        { name: "Unit", value: product?.unit || 'pcs' },
                                        { name: "Stock", value: product?.inStock ? 'In Stock' : 'Out of Stock' },
                                    ]).map((spec, idx) => (
                                        <div key={idx} className="flex justify-between py-3 border-b border-gray-100 group hover:bg-gray-50 px-2 rounded-lg transition-colors">
                                            <span className="text-gray-500 font-medium">{spec.name}:</span>
                                            <span className={`font-semibold text-right ${spec.name.toLowerCase().includes('stock')
                                                ? (spec.value === 'In Stock' ? 'text-green-600' : 'text-red-500')
                                                : 'text-[#111827]'
                                                }`}>
                                                {spec.value}
                                            </span>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}

                        {activeTab === 'reviews' && (
                            <div className="animate-in fade-in duration-300">
                                <ProductReviews
                                    reviews={reviews}
                                    averageRating={averageRating}
                                    totalReviews={reviews.length}
                                    onWriteReview={() => setIsReviewFormOpen(true)}
                                />
                            </div>

                        )}
                    </div>
                </motion.div>

                {/* Related Products */}
                {/* <RelatedProducts products={relatedProducts} /> */}

                <ReviewFormModal
                    isOpen={isReviewFormOpen}
                    onClose={() => setIsReviewFormOpen(false)}
                    onSubmit={handleReviewSubmit}
                    productName={product.name}
                />
            </div>
        </motion.div>
    );
}

