  };
  rating: number[];
  availability: ('inStock' | 'outOfStock')[];
  badges: string[];
}

// Sort Options
export type SortOption =
  | 'popular'
  | 'price-low'
  | 'price-high'
  | 'newest'
  | 'rating'
  | 'name-az'
  | 'name-za';

export interface SortConfig {
